INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('agent', 'AI Agent', 'ai', 'agent', 'Autonomous AI agent that reasons, makes decisions, and optionally calls tools. REQUIRES a pre-created agent entity - create with agent(action=''create'') first, then reference by UUID.', '{"prompt": {"type": "string", "required": false, "description": "Per-execution instruction. MUST reference data from previous nodes using {{type:label.output.field}} syntax - the agent receives NOTHING automatically. Example: ''Analyze this data: {{mcp:fetch.output.body}}''"}, "agent_id": {"type": "string", "required": true, "description": "UUID of the agent entity. Create first: agent(action=''create'', name=''...'', system_prompt=''...'')"}, "withMemory": {"type": "boolean", "default": true, "required": false, "description": "Enable conversation memory for the agent"}}'::jsonb, '{"model": {"type": "string", "description": "Model used"}, "content": {"type": "string", "description": "Alias for response (compatibility)"}, "provider": {"type": "string", "description": "AI provider"}, "response": {"type": "string", "description": "Agent final response text"}, "durationMs": {"type": "number", "description": "Execution duration in milliseconds"}, "tool_calls": {"type": "number", "description": "Count of tool calls made"}, "tokens_used": {"type": "number", "description": "Total tokens consumed"}, "promptTokens": {"type": "number", "description": "Prompt tokens used"}, "iterations_used": {"type": "number", "description": "Number of tool call iterations"}, "completionTokens": {"type": "number", "description": "Completion tokens used"}, "tool_calls_detail": {"type": "array", "description": "Detailed tool call info (name, input, output)"}}'::jsonb, NULL, NULL, '["CRITICAL - DATA FLOW: Nodes do NOT receive data automatically from predecessors. You MUST pass data explicitly via {{type:label.output.field}} in the prompt parameter. Without this, the agent has NO context about previous steps.", "MANDATORY: Create agent entity BEFORE adding to workflow. Use agent(action=''help'') for all creation parameters.", "Step 1: agent(action=''create'', name=''...'', system_prompt=''...'') → returns UUID", "Step 2: workflow_builder(action=''add_node'', type=''agent'', label=''...'', params={agent_id: ''<uuid>'', prompt: ''Analyze: {{mcp:fetch.output.data}}''}, connect_after=''...'')", "Variable syntax by node type: {{trigger:label.output.field}}, {{mcp:label.output.field}}, {{agent:label.output.response}}, {{core:label.output.field}}, {{table:label.output.field}}", "Agent entity defines: system prompt, model, temperature, tools access. Workflow node defines: per-execution prompt (with dynamic data), label, connections.", "Tools: Configured on agent entity. Default=ALL tools. Use tools_mode=''none'' or tools_mode=''custom'' with tools=[...] during agent(action=''create'')"]'::jsonb, '["agent(action=''create'', name=''Analyzer'', system_prompt=''You analyze data and return insights.'') → <uuid>", "workflow_builder(action=''add_node'', type=''agent'', label=''Analyze'', params={agent_id: ''<uuid>'', prompt: ''Analyze this data: {{trigger:start.output.email_body}}''}, connect_after=''Start'')", "workflow_builder(action=''add_node'', type=''agent'', label=''Summarize'', params={agent_id: ''<uuid>'', prompt: ''Summarize: {{agent:Analyze.output.response}}''}, connect_after=''Analyze'')"]'::jsonb, '["agent","ai","llm","gpt","claude","assistant","bot","intelligent"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('aggregate', 'Aggregate', 'control_flow', 'core', 'Aggregate: N item contexts → 1 output (DATA TRANSFORMATION). Collects results from N parallel item contexts (from Split) and reduces them into arrays. Has 1 input branch (not N branches like Merge). Counterpart to Split: Split spawns N contexts, Aggregate reduces them back to 1.', '{"fields": {"type": "array", "example": "[{label: ''ids'', expression: ''{{mcp:step.output.id}}''}]", "minItems": 1, "required": true, "description": "Array of {label, expression} defining what to collect from each item. Aliases accepted: mappings, transformations, values, aggregations, collect, outputs"}}'::jsonb, '{"fields": {"type": "object", "description": "Aggregated arrays keyed by configured field labels"}, "<label>": {"type": "array", "description": "Collected values for each configured aggregation field"}, "aggregated_count": {"type": "number", "description": "Number of items aggregated"}}'::jsonb, NULL, NULL, '["Has 1 INPUT BRANCH (not N branches like Merge)", "The N comes from ITEM CONTEXTS, not branches", "Aggregate vs Merge: Aggregate=1 branch (N items), Merge=N branches", "Use after Split to collect parallel item results"]'::jsonb, '["workflow_builder(action=''add_node'', type=''aggregate'', label=''Collect Results'', params={fields: [{label: ''message_ids'', expression: ''{{mcp:send_email.output.message_id}}''}, {label: ''statuses'', expression: ''{{mcp:send_email.output.status}}''}]}, connect_after=''Send Email'')", "workflow_builder(action=''add_node'', type=''aggregate'', label=''Gather IDs'', params={fields: [{label: ''user_ids'', expression: ''{{mcp:create_user.output.id}}''}]}, connect_after=''Create User'')"]'::jsonb, '["aggregate","collect","combine","reduce","sum","gather","summarize","rollup"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('approval', 'User Approval', 'control_flow', 'core', 'Pauses workflow execution until a user approves or rejects. Has three ports: approved (user approved), rejected (user rejected), timeout (no response within time limit). Supports role-based approval and multi-level approval thresholds.', '{"message": {"type": "string", "example": "Please review order #{{mcp:fetch.output.order_id}}", "required": false, "description": "Message shown to approver explaining what needs approval."}, "timeout_ms": {"type": "integer", "default": 86400000, "example": 86400000, "required": false, "description": "Timeout in milliseconds. Default: 86400000 (24 hours)."}, "approver_roles": {"type": "array", "default": [], "example": ["manager"], "required": false, "description": "List of roles that can approve (e.g., [''manager'', ''admin'']). Empty = any user."}, "required_approvals": {"type": "integer", "default": 1, "example": 1, "required": false, "description": "Number of approvals needed (for multi-level approval)."}}'::jsonb, '{"resolution": {"type": "string", "description": "Resolution outcome: APPROVED, REJECTED, or TIMEOUT"}, "resolved_at": {"type": "string", "description": "ISO timestamp when the approval was resolved"}, "resolved_by": {"type": "string", "description": "User ID who approved/rejected, or system for timeout"}, "signal_type": {"type": "string", "description": "Signal type (USER_APPROVAL)"}, "selected_port": {"type": "string", "description": "Port name for routing: approved, rejected, or timeout"}}'::jsonb, NULL, '{"ports": ["approved", "rejected", "timeout"], "pattern": "core:label:approved, core:label:rejected, core:label:timeout"}'::jsonb, '["Approval has 3 ports: approved, rejected, timeout - connect EACH to a different target", "Workflow PAUSES at this node until a human responds or timeout expires", "Use approver_roles to restrict who can approve (empty = anyone)", "Use required_approvals > 1 for multi-level approval chains", "Default timeout is 24 hours (86400000 ms)"]'::jsonb, '["workflow_builder(action=''add_node'', type=''approval'', label=''Manager Review'', params={approver_roles: [''manager''], message: ''Review order #{{mcp:fetch.output.id}}''}, connect_after=''Prepare Order'')", "workflow_builder(action=''connect'', from=''core:manager_review:approved'', to=''Process Order'')", "workflow_builder(action=''connect'', from=''core:manager_review:rejected'', to=''Cancel Order'')", "workflow_builder(action=''connect'', from=''core:manager_review:timeout'', to=''Send Reminder'')"]'::jsonb, '["approval","approve","reject","human","review","authorize","permission","gate","manual","timeout"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('chat', 'Chat Trigger', 'trigger', 'trigger', 'Triggers workflow when user sends a chat message.', '{}'::jsonb, '{"message": {"type": "string", "description": "Raw user message content"}, "triggered_at": {"type": "string", "description": "ISO timestamp when trigger fired"}, "conversation_id": {"type": "string", "description": "Conversation ID (if available)"}}'::jsonb, NULL, NULL, '["Responds to user messages in conversation interface", "Each message belongs to a conversation_id"]'::jsonb, '["workflow_builder(action=''add_node'', type=''chat'', label=''User Message'')"]'::jsonb, '["chat","message","conversation","user","input","text"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('classify', 'Classify', 'ai', 'agent', 'Flow: 1 → N exclusive. AI analyzes content and routes to ONE category based on semantic understanding.', '{"label": {"type": "string", "required": true, "description": "Unique label for this node"}, "model": {"type": "string", "default": "claude-sonnet-4-20250514", "required": false}, "prompt": {"type": "string", "required": true, "description": "Classification instruction INCLUDING the data to classify. MUST include {{type:label.output.field}} to reference actual data - the node receives NOTHING automatically. Example: ''Classify this support ticket by issue type: {{trigger:form.output.description}}''"}, "provider": {"enum": ["openai", "anthropic", "google", "mistral", "deepseek"], "type": "string", "default": "openai", "required": false, "description": "AI provider to use"}, "categories": {"type": "array", "minItems": 2, "required": true, "description": "Array of {label, description} objects. AI uses description to understand each category. Example: [{label: ''billing'', description: ''Payment and invoice issues''}, {label: ''technical'', description: ''Bugs and errors''}]"}, "temperature": {"max": 1, "min": 0, "type": "number", "default": 0.3, "required": false, "description": "Lower = more consistent"}}'::jsonb, '{"model": {"type": "string", "description": "Model used"}, "provider": {"type": "string", "description": "AI provider"}, "confidence": {"type": "number", "description": "Confidence score between 0 and 1"}, "tokens_used": {"type": "number", "description": "Total tokens consumed"}, "selected_category": {"type": "string", "description": "The category label selected by the AI"}}'::jsonb, NULL, '{"note": "N = array index (0-based). Creates 1 port per category.", "example": "categories: [{billing}, {technical}, {other}] → category_0 (billing), category_1 (technical), category_2 (other)", "pattern": "agent:label:category_N"}'::jsonb, '["CRITICAL - DATA FLOW: The prompt parameter MUST include data from a previous node using {{type:label.output.field}} syntax. Writing just ''Classify the message'' gives the node NO data to work with.", "The prompt contains BOTH the instruction AND the data reference. Example: ''Classify this ticket by type: {{trigger:form.output.description}}''", "SEMANTIC ROUTING: AI understands meaning, not just values", "vs Decision: Decision = explicit conditions (status==''active''), Classify = AI understands content", "vs Switch: Switch = exact value match, Classify = semantic understanding", "ONE category selected (exclusive). Confidence indicates certainty.", "Variable syntax: {{trigger:label.output.field}}, {{mcp:label.output.field}}, {{agent:label.output.response}}, {{core:label.output.field}}"]'::jsonb, '["workflow_builder(action=''add_node'', type=''classify'', label=''Route Ticket'', params={prompt: ''Classify this support ticket by issue type: {{trigger:form.output.description}}'', categories: [{label: ''billing'', description: ''Payment and invoice issues''}, {label: ''technical'', description: ''Bugs and errors''}]}, connect_after=''Form'')", "workflow_builder(action=''add_node'', type=''agent'', label=''Handle Bug'', params={agent_id: ''<uuid>'', prompt: ''Fix: {{trigger:form.output.description}}''}, connect_after=''Route Ticket:category_1'')"]'::jsonb, '["classify","categorize","route","branch","ai","classification","sort","tag"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('code', 'Code', 'utility', 'core', 'Execute custom code in JavaScript, Python, TypeScript, or Bash via a sandboxed Piston runtime. User code receives upstream data as $input (JS/TS), _input (Python), or INPUT (Bash). Set $output/_output/OUTPUT to pass structured results downstream.', '{"code": {"type": "string", "required": true, "description": "The code to execute. Use $input to access upstream data, set $output to return results."}, "language": {"type": "string", "default": "javascript", "required": false, "description": "Programming language: javascript, python, typescript, bash."}, "timeoutSeconds": {"type": "integer", "default": 10, "required": false, "description": "Maximum execution time in seconds (1-30)."}}'::jsonb, '{"result": {"type": "any", "description": "Structured result set by $output/_output in user code"}, "stderr": {"type": "string", "description": "Standard error output"}, "stdout": {"type": "string", "description": "Console output (excluding result line)"}, "success": {"type": "boolean", "description": "Whether execution succeeded"}, "exitCode": {"type": "number", "description": "Process exit code (0 = success)"}, "language": {"type": "string", "description": "Language used for execution"}, "executionTime": {"type": "number", "description": "Execution time in milliseconds"}}'::jsonb, NULL, NULL, '["Supported languages: javascript, python, typescript, bash", "In JS/TS: upstream data available as $input, set $output for results", "In Python: upstream data available as _input, set _output for results", "In Bash: upstream data available as $INPUT env var, write to $OUTPUT file", "Code runs in a sandboxed Piston container with configurable timeout", "Access results: {{core:label.output.result.field_name}}"]'::jsonb, E'["workflow_builder(action=''add_node'', type=''code'', label=''Transform Data'', params={language: ''javascript'', code: ''$output = { total: $input.items.length }''})", "workflow_builder(action=''add_node'', type=''code'', label=''Process CSV'', params={language: ''python'', code: ''import json; _output = {\\"count\\": len(json.loads(_input)[\\"rows\\"])}''}, connect_after=''Fetch Data'')"]'::jsonb, '["code","script","javascript","python","typescript","bash","execute","run","custom","transform","compute"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('compare_datasets', 'Compare Datasets', 'data_manipulation', 'core', 'Compares two datasets (lists of items) and categorizes each item as matched (in both), only in A, or only in B. Matching is based on specified fields or all fields if none are specified. Returns the comparison results along with counts.', '{"inputA": {"type": "string", "required": true, "description": "Expression referencing the first dataset (e.g., step output key or SpEL expression resolving to a list of items)."}, "inputB": {"type": "string", "required": true, "description": "Expression referencing the second dataset (e.g., step output key or SpEL expression resolving to a list of items)."}, "matchFields": {"type": "array", "items": "string", "default": [], "required": false, "description": "List of field names to use as match keys. If empty, all fields are compared."}, "returnOnlyA": {"type": "boolean", "default": true, "required": false, "description": "Whether to include items only in dataset A in the output."}, "returnOnlyB": {"type": "boolean", "default": true, "required": false, "description": "Whether to include items only in dataset B in the output."}, "returnMatched": {"type": "boolean", "default": true, "required": false, "description": "Whether to include items found in both datasets in the output."}}'::jsonb, '{"totalA": {"type": "number", "description": "Total items in dataset A"}, "totalB": {"type": "number", "description": "Total items in dataset B"}, "matched": {"type": "array", "description": "Items found in both datasets"}, "onlyInA": {"type": "array", "description": "Items only in dataset A"}, "onlyInB": {"type": "array", "description": "Items only in dataset B"}, "success": {"type": "boolean", "description": "Whether comparison succeeded"}, "matchFields": {"type": "array", "description": "Fields used for matching"}, "matchedCount": {"type": "number", "description": "Number of matched items"}, "onlyInACount": {"type": "number", "description": "Number of items only in A"}, "onlyInBCount": {"type": "number", "description": "Number of items only in B"}}'::jsonb, NULL, NULL, '["Use matchFields to specify which fields determine if two items are the same", "If matchFields is empty, all fields are compared (exact match)", "Matched items use dataset A''s version of the item", "Disable returnMatched/returnOnlyA/returnOnlyB flags to reduce output size", "Access results: {{core:label.output.matched}}, {{core:label.output.onlyInA}}, {{core:label.output.onlyInB}}", "Access counts: {{core:label.output.matchedCount}}, {{core:label.output.onlyInACount}}, {{core:label.output.onlyInBCount}}"]'::jsonb, '["workflow_builder(action=''add_node'', type=''compare_datasets'', label=''Compare Users'', params={inputA: ''{{mcp:fetch_old_users.output.items}}'', inputB: ''{{mcp:fetch_new_users.output.items}}'', matchFields: [''email''], returnMatched: true, returnOnlyA: true, returnOnlyB: true}, connect_after=''Fetch New Users'')", "workflow_builder(action=''add_node'', type=''compare_datasets'', label=''Diff Products'', params={inputA: ''{{mcp:catalog_a.output.products}}'', inputB: ''{{mcp:catalog_b.output.products}}'', matchFields: [''sku'', ''region''], returnMatched: false, returnOnlyA: true, returnOnlyB: true}, connect_after=''Catalog B'')", "workflow_builder(action=''add_node'', type=''compare_datasets'', label=''Find Common'', params={inputA: ''{{mcp:list_a.output.items}}'', inputB: ''{{mcp:list_b.output.items}}'', matchFields: [''id''], returnMatched: true, returnOnlyA: false, returnOnlyB: false}, connect_after=''List B'')"]'::jsonb, '["compare","diff","difference","datasets","merge","match","intersection","venn","only","common","overlap","reconcile","sync"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('compression', 'Compression', 'data_manipulation', 'core', 'Compress or decompress data using gzip, zip, deflate, or base64 formats. Compress converts a string to base64-encoded compressed data. Decompress converts base64-encoded compressed data back to the original string.', '{"value": {"type": "string", "required": true, "description": "Input value (string to compress or base64 to decompress, supports SpEL)."}, "format": {"type": "string", "default": "gzip", "required": false, "description": "Compression format: gzip, zip, deflate, or base64."}, "filename": {"type": "string", "required": false, "description": "Optional filename for the compressed output."}, "operation": {"type": "string", "default": "compress", "required": false, "description": "Operation to perform: compress or decompress."}}'::jsonb, '{"format": {"type": "string", "description": "Compression format used"}, "result": {"type": "any", "description": "Compression or decompression result"}, "success": {"type": "boolean", "description": "Whether the operation succeeded"}, "operation": {"type": "string", "description": "The operation performed (compress/decompress)"}}'::jsonb, NULL, NULL, '["Supported formats: gzip, zip, deflate, base64", "Compress converts string to base64-encoded compressed data", "Decompress converts base64-encoded compressed data back to original string", "Access result: {{core:label.output.result}}"]'::jsonb, '["workflow_builder(action=''add_node'', type=''compression'', label=''Compress Data'', params={operation: ''compress'', format: ''gzip'', value: ''{{trigger:webhook.output.payload}}''}, connect_after=''Webhook'')", "workflow_builder(action=''add_node'', type=''compression'', label=''Decompress Data'', params={operation: ''decompress'', format: ''gzip'', value: ''{{mcp:fetch_data.output.compressed_data}}''}, connect_after=''Fetch Data'')"]'::jsonb, '["compress","decompress","gzip","deflate","compression","zip","encode","decode","base64"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('convert_to_file', 'Convert to File', 'data_manipulation', 'core', 'Exports JSON data (List of Maps) to file content in CSV, XLSX, JSON, or TXT format. The input data is resolved from a previous step output. CSV supports custom delimiters and optional headers. XLSX produces Base64-encoded Excel files using Apache POI. JSON outputs pretty-printed arrays. TXT outputs key=value pairs separated by blank lines.', E'{"value": {"type": "string", "required": false, "description": "Expression referencing the step output containing the data to convert (List of Maps). Supports SpEL templates like {{step.output.field}}. If not provided, falls back to trigger data."}, "format": {"enum": ["csv", "xlsx", "json", "txt"], "type": "string", "default": "csv", "required": false, "description": "Output file format: ''csv'' (comma-separated values), ''xlsx'' (Excel spreadsheet as Base64), ''json'' (pretty-printed JSON array), or ''txt'' (key=value plain text)."}, "filename": {"type": "string", "default": "export", "required": false, "description": "Base filename for the output (without extension). Extension is added automatically based on format."}, "delimiter": {"type": "string", "default": ",", "required": false, "description": "Delimiter character for CSV format. Common values: '','' (comma), '';'' (semicolon), ''\\\\t'' (tab). Ignored for other formats."}, "includeHeaders": {"type": "boolean", "default": true, "required": false, "description": "Whether to include column headers as the first row in CSV and XLSX output. Ignored for JSON and TXT formats."}}'::jsonb, '{"size": {"type": "number", "description": "File size in bytes"}, "format": {"type": "string", "description": "Output file format"}, "result": {"type": "string", "description": "URL or reference to the converted file"}, "success": {"type": "boolean", "description": "Whether conversion succeeded"}, "filename": {"type": "string", "description": "Generated file name"}, "rowCount": {"type": "number", "description": "Number of rows in the file"}}'::jsonb, NULL, NULL, '["Input data should be a List of Maps (rows of key-value pairs) from a previous step output", "CSV fields containing the delimiter, quotes, or newlines are automatically escaped", "XLSX output is Base64-encoded - decode to get the binary .xlsx file", "JSON output is a pretty-printed array of objects", "TXT output uses key=value format with rows separated by blank lines", "If no step output is found, trigger data is used as a single-row fallback", "Access result: {{core:label.output.result}}", "Access filename: {{core:label.output.filename}}", "Access row count: {{core:label.output.rowCount}}"]'::jsonb, '["workflow_builder(action=''add_node'', type=''convert_to_file'', label=''Export CSV'', params={format: ''csv'', value: ''query_results'', filename: ''users_export'', delimiter: '','', includeHeaders: true}, connect_after=''Query Users'')", "workflow_builder(action=''add_node'', type=''convert_to_file'', label=''Generate Report'', params={format: ''xlsx'', value: ''report_data'', filename: ''monthly_report'', includeHeaders: true}, connect_after=''Aggregate Data'')", "workflow_builder(action=''add_node'', type=''convert_to_file'', label=''Export JSON'', params={format: ''json'', value: ''api_results'', filename: ''backup''}, connect_after=''Fetch Data'')", "workflow_builder(action=''add_node'', type=''convert_to_file'', label=''Export Text'', params={format: ''txt'', value: ''log_entries'', filename: ''audit_log''}, connect_after=''Collect Logs'')"]'::jsonb, '["convert","file","export","csv","xlsx","excel","json","txt","text","download","spreadsheet","report","data"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('create_column', 'Create Column', 'table', 'table', 'Creates new columns on a datasource table.', '{"columns": {"type": "array", "required": true, "description": "Array of column definitions to create"}, "table_id": {"type": "number", "required": true, "description": "ID of the table to add columns to"}}'::jsonb, '{"created_at": {"type": "string", "description": "ISO timestamp of creation"}, "column_count": {"type": "number", "description": "Number of columns created"}, "created_columns": {"type": "array", "description": "List of created column definitions"}}'::jsonb, NULL, NULL, NULL, NULL, NULL, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('crypto_jwt', 'Crypto / JWT', 'data_manipulation', 'core', 'Provides cryptographic operations and JWT management. Supports hashing (MD5, SHA-1, SHA-256, SHA-512), HMAC signing/verification (HmacSHA256, HmacSHA512), AES encryption/decryption, JWT creation/decoding/verification (HS256), Base64 encoding/decoding, UUID generation, and random secret generation.', '{"key": {"type": "string", "required": false, "description": "Encryption key for AES encrypt/decrypt operations."}, "token": {"type": "string", "required": false, "description": "JWT token for jwtDecode/jwtVerify, or HMAC signature for hmacVerify."}, "value": {"type": "string", "required": false, "description": "Input value for hash, hmacSign, encrypt, decrypt, base64Encode, base64Decode operations."}, "secret": {"type": "string", "required": false, "description": "Secret for HMAC and JWT operations."}, "payload": {"type": "object", "required": false, "description": "JWT payload claims for jwtCreate operation."}, "encoding": {"enum": ["hex", "base64"], "type": "string", "default": "hex", "required": false, "description": "Output encoding format."}, "algorithm": {"type": "string", "default": "SHA-256", "required": false, "description": "Algorithm to use. For hash: MD5, SHA-1, SHA-256, SHA-512. For HMAC: HmacSHA256, HmacSHA512. For encrypt/decrypt: AES."}, "operation": {"enum": ["hash", "hmacSign", "hmacVerify", "encrypt", "decrypt", "jwtCreate", "jwtDecode", "jwtVerify", "base64Encode", "base64Decode", "generateUuid", "generateSecret"], "type": "string", "required": true, "description": "The cryptographic operation to perform."}}'::jsonb, '{"result": {"type": "any", "description": "Operation result (string, boolean, or map depending on operation)"}, "operation": {"type": "string", "description": "The operation that was performed"}}'::jsonb, NULL, NULL, '["hash operation requires ''value'' parameter, returns hex digest", "hmacSign requires ''value'' and ''secret'', returns hex HMAC signature", "hmacVerify requires ''value'', ''secret'', and ''token'' (signature to verify), returns boolean", "encrypt requires ''value'' and ''key'', uses AES/CBC/PKCS5Padding, returns base64 ciphertext", "decrypt requires ''value'' (base64 ciphertext) and ''key'', returns plaintext", "jwtCreate requires ''secret'' and ''payload'' (map of claims), creates HS256 JWT", "jwtDecode requires ''token'', returns map with header, payload, signature (no verification)", "jwtVerify requires ''token'' and ''secret'', returns boolean indicating valid signature", "base64Encode/base64Decode require ''value''", "generateUuid and generateSecret require no parameters", "Access result: {{core:label.output.result}}", "AES encryption uses a key derived from SHA-256 hash of the provided key string"]'::jsonb, '["workflow_builder(action=''add_node'', type=''crypto_jwt'', label=''Hash Password'', params={operation: ''hash'', algorithm: ''SHA-256'', value: ''{{trigger:start.output.password}}''}, connect_after=''Start'')", "workflow_builder(action=''add_node'', type=''crypto_jwt'', label=''Create Token'', params={operation: ''jwtCreate'', secret: ''my-secret'', payload: {sub: ''{{mcp:get_user.output.user_id}}'', role: ''admin''}}, connect_after=''Get User'')", "workflow_builder(action=''add_node'', type=''crypto_jwt'', label=''Verify Token'', params={operation: ''jwtVerify'', secret: ''my-secret'', token: ''{{trigger:webhook.output.authorization}}''}, connect_after=''Webhook'')", "workflow_builder(action=''add_node'', type=''crypto_jwt'', label=''Encrypt Data'', params={operation: ''encrypt'', key: ''encryption-key'', value: ''{{mcp:fetch_data.output.sensitive_field}}''}, connect_after=''Fetch Data'')", "workflow_builder(action=''add_node'', type=''crypto_jwt'', label=''Generate ID'', params={operation: ''generateUuid''}, connect_after=''Start'')"]'::jsonb, '["crypto","jwt","hash","encrypt","decrypt","hmac","sign","verify","base64","encode","decode","uuid","secret","token","sha","md5","aes","security"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('data_input', 'Data Input', 'core', 'core', 'Provides multiple labeled text and/or file inputs to the workflow. Each item has a user-defined label that becomes an output field, making downstream references readable.', '{"items": {"type": "array", "required": true, "description": "Array of input items, each with: id (auto-generated), label (output field name), type (text or file), text (SpEL expression for text type), file (file object for file type)"}}'::jsonb, '{"<label>": {"type": "any", "description": "Each configured item label becomes an output field. Text items resolve to string, file items resolve to file object."}, "input_data": {"type": "object", "description": "Map of all resolved input values keyed by label"}}'::jsonb, NULL, NULL, '["Each item label becomes a top-level output field: {{core:my_input.output.prompt}}", "Text items support SpEL templates for dynamic values", "File items pass through pre-uploaded file objects as-is", "Use input_data to access all resolved values as a single object"]'::jsonb, '["workflow_builder(action=''add_node'', type=''data_input'', label=''My Input'', params={items: [{label: ''prompt'', type: ''text'', text: ''Analyze this data: {{trigger:start.output.message}}''}, {label: ''context'', type: ''text'', text: ''Additional context here''}]}, connect_after=''Start'')"]'::jsonb, '["data_input","input","text","file","labeled","provide","inject","static","dynamic"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('date_time', 'DateTime', 'data_manipulation', 'core', 'Parses, formats, converts, and manipulates date/time values. Supports operations: parse (string to date), format (date to string), convertTimezone, add/subtract durations, difference between dates, extract parts (year, month, day, etc.), and get current time. Uses ISO-8601 and custom format patterns.', '{"value": {"type": "string", "required": false, "description": "The date/time value to operate on. Required for all operations except ''now''. Accepts ISO-8601, LocalDateTime, or custom formatted strings."}, "timezone": {"type": "string", "default": "UTC", "required": false, "description": "Source timezone (e.g., ''UTC'', ''Europe/Paris'', ''America/New_York'')."}, "operation": {"enum": ["parse", "format", "convertTimezone", "add", "subtract", "difference", "extract", "now"], "type": "string", "default": "format", "required": true, "description": "The date/time operation to perform."}, "extractPart": {"enum": ["year", "month", "day", "hour", "minute", "second", "dayOfWeek", "dayOfYear"], "type": "string", "required": false, "description": "Part to extract from the date/time."}, "inputFormat": {"type": "string", "required": false, "description": "Custom date/time pattern for parsing the input value (e.g., ''dd/MM/yyyy'', ''yyyy-MM-dd HH:mm:ss''). If omitted, ISO-8601 parsing is attempted."}, "secondValue": {"type": "string", "required": false, "description": "Second date/time value for the difference operation."}, "durationUnit": {"enum": ["years", "months", "days", "hours", "minutes", "seconds"], "type": "string", "default": "days", "required": false, "description": "Unit for add/subtract/difference operations."}, "outputFormat": {"type": "string", "required": false, "description": "Custom date/time pattern for formatting the output (e.g., ''yyyy-MM-dd'', ''HH:mm:ss''). If omitted, ISO-8601 instant format is used."}, "durationAmount": {"type": "number", "default": 0, "required": false, "description": "Amount to add or subtract."}, "targetTimezone": {"type": "string", "required": false, "description": "Target timezone for convertTimezone operation."}}'::jsonb, '{"result": {"type": "string", "description": "The formatted or computed date/time value"}, "operation": {"type": "string", "description": "The operation that was performed"}}'::jsonb, NULL, NULL, '["Use ''parse'' to convert user-supplied date strings into ISO format for downstream processing", "Use ''format'' to display dates in human-readable patterns (e.g., dd/MM/yyyy)", "Use ''convertTimezone'' to adjust dates between timezones (e.g., UTC to America/New_York)", "Use ''add'' or ''subtract'' with durationUnit and durationAmount to calculate future/past dates", "Use ''difference'' with secondValue to calculate elapsed time between two dates", "Use ''extract'' to get individual components (year, month, day, hour, etc.) for conditional logic", "Use ''now'' to get the current date/time in a specific timezone", "Default timezone is UTC when not specified", "Access result: {{core:label.output.result}}", "For difference results: {{core:label.output.result.totalDays}}, {{core:label.output.result.difference}}"]'::jsonb, '["workflow_builder(action=''add_node'', type=''date_time'', label=''Format Date'', params={dateTime: {operation: ''format'', value: ''{{trigger:start.output.created_at}}'', outputFormat: ''dd MMM yyyy''}}, connect_after=''Start'')", "workflow_builder(action=''add_node'', type=''date_time'', label=''Add 7 Days'', params={dateTime: {operation: ''add'', value: ''{{trigger:start.output.due_date}}'', durationUnit: ''days'', durationAmount: 7, outputFormat: ''yyyy-MM-dd''}}, connect_after=''Get Task'')", "workflow_builder(action=''add_node'', type=''date_time'', label=''Convert To Local'', params={dateTime: {operation: ''convertTimezone'', value: ''{{trigger:start.output.timestamp}}'', timezone: ''UTC'', targetTimezone: ''Europe/Paris'', outputFormat: ''yyyy-MM-dd HH:mm:ss''}}, connect_after=''Fetch Event'')", "workflow_builder(action=''add_node'', type=''date_time'', label=''Get Current Time'', params={dateTime: {operation: ''now'', timezone: ''UTC'', outputFormat: ''yyyy-MM-dd HH:mm:ss''}}, connect_after=''Start'')", "workflow_builder(action=''add_node'', type=''date_time'', label=''Days Until Deadline'', params={dateTime: {operation: ''difference'', value: ''{{core:get_current_time.output.result}}'', secondValue: ''{{trigger:start.output.deadline}}'', durationUnit: ''days''}}, connect_after=''Get Current Time'')"]'::jsonb, '["date","time","datetime","format","parse","timezone","convert","add","subtract","difference","extract","now","duration","calendar","timestamp","iso","utc"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('decision', 'Decision (If/Else)', 'control_flow', 'core', 'Decision: Exclusive branching based on boolean conditions. Evaluates conditions in order, executes ONLY the first branch whose condition is true. Has ports: if, elseif_0, elseif_1, ..., else. Only ONE branch executes (unlike Fork where ALL branches run).', '{"conditions": {"type": "array", "example": "[{condition: ''{{mcp:check.output.score}} > 80'', label: ''High''}, {condition: ''default'', label: ''Low''}]", "minItems": 1, "required": true, "description": "Array of {condition, label}. First match wins. Use ''default'' or ''true'' as last condition for else branch. Each item accepts: condition/expression/expr for the expression, label/name for the branch name"}}'::jsonb, '{"evaluations": {"type": "array", "description": "Detailed evaluation results per branch, each with branch_type, condition, resolved_condition, and result"}, "selected_branch": {"type": "string", "description": "The single branch that was selected (first-true-wins)"}, "condition_result": {"type": "boolean", "description": "Whether any branch matched"}, "skipped_branches": {"type": "array", "description": "Branches that were not executed"}, "condition_expression": {"type": "string", "description": "Expression of the selected branch"}, "selected_branch_index": {"type": "number", "description": "Index of the selected branch (-1 if none matched)"}}'::jsonb, NULL, '{"ports": ["if", "elseif_0", "elseif_1", "...", "else"], "pattern": "core:label:if, core:label:elseif_N, core:label:else"}'::jsonb, '["Exclusive branching: only ONE branch executes", "First true wins, then stops evaluation", "Always include default as last condition"]'::jsonb, '["workflow_builder(action=''add_node'', type=''decision'', label=''Check Score'', params={conditions: [{condition: ''{{mcp:evaluate.output.score}} >= 80'', label: ''Pass''}, {condition: ''default'', label: ''Fail''}]}, connect_after=''Evaluate'')", "workflow_builder(action=''add_node'', type=''decision'', label=''Route By Status'', params={conditions: [{condition: ''{{mcp:check.output.status}} == ''''active'''''', label: ''Active''}, {condition: ''{{mcp:check.output.status}} == ''''pending'''''', label: ''Pending''}, {condition: ''default'', label: ''Other''}]}, connect_after=''Check'')"]'::jsonb, '["decision","if","else","condition","branch","conditional"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('delete_row', 'Delete Row', 'action', 'table', 'Delete rows matching a WHERE condition.', '{"where": {"type": "object", "required": true, "description": "{column, operator, value}"}, "table_id": {"type": "integer", "required": true}}'::jsonb, '{"deleted_at": {"type": "string", "description": "ISO timestamp of deletion"}, "deleted_count": {"type": "number", "description": "Number of rows deleted"}}'::jsonb, NULL, NULL, NULL, '["workflow_builder(action=''add_node'', type=''delete_row'', label=''Remove Item'', params={table_id: 123, where: {column: ''id'', operator: ''=='', value: ''{{trigger:webhook.output.item_id}}''}}, connect_after=''Webhook'')"]'::jsonb, '["delete","remove","drop","destroy","erase","row","table"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('download_file', 'Download File', 'control_flow', 'core', 'Download File: Download a file from a URL and make it available in the workflow. Supports custom headers and timeouts. Returns file path, name, size, and content type.', '{"url": {"type": "string", "example": "{{mcp:get_report.output.download_url}}", "required": true, "description": "URL to download from. Also accepts: source, link, file_url, href, src"}, "headers": {"type": "object", "required": false, "description": "Custom HTTP headers as key-value pairs"}, "timeout": {"type": "integer", "default": 30000, "required": false, "description": "Download timeout in milliseconds (default: 30000)"}, "filename": {"type": "string", "required": false, "description": "Output filename. Also accepts: file_name, output. Auto-detected from URL if omitted"}}'::jsonb, '{"file_url": {"type": "string", "description": "Storage URL of the downloaded file"}, "file_name": {"type": "string", "description": "File name"}, "file_size": {"type": "number", "description": "File size in bytes"}, "source_url": {"type": "string", "description": "Original source URL that was downloaded"}, "content_type": {"type": "string", "description": "MIME type"}}'::jsonb, NULL, NULL, '["Use headers for authentication", "Large files may need extended timeout"]'::jsonb, '["workflow_builder(action=''add_node'', type=''download_file'', label=''Download Report'', params={url: ''{{mcp:generate_report.output.url}}''}, connect_after=''Generate Report'')", "workflow_builder(action=''add_node'', type=''download_file'', label=''Get CSV'', params={url: ''https://example.com/data.csv'', filename: ''export.csv''}, connect_after=''Start'')"]'::jsonb, '["download","file","fetch","image","document","media","pdf","url"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('error', 'Error Trigger', 'trigger', 'trigger', 'Fires when a referenced workflow fails (FAILED or PARTIAL_SUCCESS status). Enables building error handler workflows that react to failures in other workflows. Includes anti-loop protection: if an error handler workflow itself fails, it will NOT trigger additional error handlers.', '{"id": {"type": "string", "required": true, "description": "The UUID of the parent workflow whose failure should trigger this workflow."}, "label": {"type": "string", "required": false, "description": "Human-readable label for this trigger (e.g., ''On Payment Failure'')."}}'::jsonb, '{"status": {"type": "string", "description": "Final status of the parent run"}, "totalSteps": {"type": "number", "description": "Total number of steps"}, "failedSteps": {"type": "number", "description": "Number of failed steps"}, "parentRunId": {"type": "string", "description": "Run ID of the parent execution"}, "triggeredAt": {"type": "string", "description": "ISO timestamp when error trigger fired"}, "errorMessage": {"type": "string", "description": "Error message from the failure"}, "skippedSteps": {"type": "number", "description": "Number of skipped steps"}, "completedSteps": {"type": "number", "description": "Number of completed steps"}, "parentWorkflowId": {"type": "string", "description": "ID of the parent workflow that failed"}}'::jsonb, NULL, NULL, '["Error triggers fire on FAILED or PARTIAL_SUCCESS status only", "Anti-loop protection: error handler workflows that fail do NOT trigger other error handlers", "The trigger id field must contain the UUID of the workflow to monitor", "Multiple error triggers can reference different workflows (multi-DAG support)", "Error handlers must have an active run (WAITING_TRIGGER) to receive dispatches", "Access error details via {{trigger:label.output.errorMessage}}, {{trigger:label.output.status}}, etc.", "Works exactly like workflow triggers but fires on failure instead of completion"]'::jsonb, '["workflow_builder(action=''add_trigger'', type=''error'', id=''<workflow-uuid>'', label=''On Order Failure'')", "workflow_builder(action=''add_trigger'', type=''error'', id=''<workflow-uuid>'', label=''On Payment Error'')"]'::jsonb, '["error","failure","fail","handler","catch","exception","on-error","error-trigger","alert","notify","recovery","fallback"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('extract_from_file', 'Extract From File', 'data_manipulation', 'core', 'Imports file content (CSV, XLSX, JSON) into structured JSON items. Parses the input data based on the specified format and outputs a list of maps representing rows or objects. Supports headers detection, custom delimiters for CSV, sheet selection for XLSX, and handles both arrays and single objects for JSON.', E'{"value": {"type": "string", "required": true, "description": "The input data to parse. For CSV/JSON: raw text content. For XLSX: Base64-encoded file content. Can use expressions like {{trigger:label.output.field}}."}, "format": {"enum": ["csv", "xlsx", "json"], "type": "string", "default": "csv", "required": false, "description": "File format to parse."}, "delimiter": {"type": "string", "default": ",", "required": false, "description": "Delimiter character for CSV parsing (e.g., '','' for comma, '';'' for semicolon, ''\\\\t'' for tab)."}, "sheetName": {"type": "string", "required": false, "description": "Name of the sheet to read from XLSX files. If not specified, reads the first sheet."}, "hasHeaders": {"type": "boolean", "default": false, "required": false, "description": "Whether the first row contains column headers. If true, header values become field names. If false, fields are named column_0, column_1, etc."}}'::jsonb, '{"items": {"type": "array", "description": "Extracted rows/items from the file"}, "format": {"type": "string", "description": "Detected file format (csv, xlsx, json, etc.)"}, "columns": {"type": "array", "description": "Column definitions detected"}, "success": {"type": "boolean", "description": "Whether extraction succeeded"}, "rowCount": {"type": "number", "description": "Number of rows extracted"}, "columnCount": {"type": "number", "description": "Number of columns detected"}}'::jsonb, NULL, NULL, '["CSV parsing supports quoted fields with commas inside quotes", "XLSX input must be Base64-encoded binary content", "JSON input can be an array of objects or a single object (wrapped into a list)", "When hasHeaders is false, columns are named column_0, column_1, etc.", "Custom delimiters allow parsing TSV (tab), PSV (pipe), and other formats", "Access extracted data: {{core:label.output.items}} (list of maps)", "Access row count: {{core:label.output.rowCount}}", "Access column names: {{core:label.output.columns}}", "Combine with Split node to iterate over extracted items"]'::jsonb, '["workflow_builder(action=''add_node'', type=''extract_from_file'', label=''Parse CSV'', params={format: ''csv'', value: ''{{trigger:upload.output.file_content}}'', delimiter: '','', hasHeaders: true}, connect_after=''Upload Trigger'')", "workflow_builder(action=''add_node'', type=''extract_from_file'', label=''Read Excel'', params={format: ''xlsx'', value: ''{{trigger:upload.output.file_base64}}'', sheetName: ''Data'', hasHeaders: true}, connect_after=''File Input'')", "workflow_builder(action=''add_node'', type=''extract_from_file'', label=''Parse JSON Data'', params={format: ''json'', value: ''{{mcp:fetch_api.output.body}}'', hasHeaders: false}, connect_after=''Fetch API'')"]'::jsonb, '["extract","import","parse","csv","xlsx","excel","json","file","read","load","convert","spreadsheet","tabular","data"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('filter', 'Filter', 'data_manipulation', 'core', 'Filters items based on conditions. Each condition specifies a field, operator, and value. Supports AND mode (all conditions must match) and OR mode (any condition must match). Unmatched items are excluded from downstream processing.', '{"mode": {"enum": ["and", "or"], "type": "string", "default": "and", "required": false, "description": "Filter mode: ''and'' (all conditions must match) or ''or'' (any condition must match)."}, "conditions": {"type": "array", "items": {"field": "string", "value": "string", "operator": "string (equals|notEquals|contains|notContains|greaterThan|lessThan|greaterOrEqual|lessOrEqual|startsWith|endsWith|isEmpty|isNotEmpty)"}, "required": true, "description": "List of filter conditions. Each condition has: field (column name), operator (comparison type), value (expected value)."}}'::jsonb, '{"data": {"type": "object", "description": "Original input data (only present when matched is true)"}, "matched": {"type": "boolean", "description": "Whether the item passed the filter conditions"}, "filter_mode": {"type": "string", "description": "The mode used for evaluation (and or or)"}, "conditions_evaluated": {"type": "number", "description": "Number of conditions evaluated"}}'::jsonb, NULL, NULL, '["Use AND mode when ALL conditions must be true to keep an item", "Use OR mode when ANY condition being true is sufficient to keep an item", "isEmpty and isNotEmpty operators do not require a value parameter", "Numeric comparisons (greaterThan, lessThan, etc.) attempt numeric parsing, fallback to string comparison", "Access filter result: {{core:label.output.matched}} (boolean)", "Access filtered data: {{core:label.output.data.field_name}}"]'::jsonb, '["workflow_builder(action=''add_node'', type=''filter'', label=''Active Users'', params={conditions: [{field: ''status'', operator: ''equals'', value: ''active''}], mode: ''and''}, connect_after=''Fetch Users'')", "workflow_builder(action=''add_node'', type=''filter'', label=''High Score'', params={conditions: [{field: ''score'', operator: ''greaterThan'', value: ''80''}, {field: ''verified'', operator: ''equals'', value: ''true''}], mode: ''and''}, connect_after=''Get Players'')", "workflow_builder(action=''add_node'', type=''filter'', label=''Important Items'', params={conditions: [{field: ''priority'', operator: ''equals'', value: ''high''}, {field: ''flagged'', operator: ''equals'', value: ''true''}], mode: ''or''}, connect_after=''List Items'')"]'::jsonb, '["filter","where","condition","match","keep","exclude","select","criteria","predicate","and","or"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('find_rows', 'Find Rows', 'table', 'table', 'Search a table and iterate over matching rows in parallel (like Split). Each matching row spawns a parallel execution context with {{item}} and {{index}} variables. Use for batch processing table data.', '{"limit": {"type": "integer", "default": 100, "required": false, "description": "Maximum number of rows to return (1-1000)."}, "where": {"type": "object", "example": {"value": "active", "column": "status", "operator": "=="}, "required": false, "description": "Filter: {column, operator, value}. Operators: ==, !=, >, <, >=, <=, contains, starts_with."}, "table_id": {"type": "integer", "required": true, "description": "ID of the table to search. Use table(action=''list'') to find available tables."}}'::jsonb, '{"items": {"type": "array", "description": "All found rows (after limit applied)"}, "find_id": {"type": "string", "description": "Node ID of the find node"}, "has_more": {"type": "boolean", "description": "Whether more rows exist beyond the limit"}, "split_id": {"type": "string", "description": "Internal split identifier"}, "max_items": {"type": "number", "description": "Configured max items cap"}, "item_count": {"type": "number", "description": "Number of items found"}, "terminated": {"type": "boolean", "description": "Whether find has terminated"}, "exit_reason": {"type": "string", "description": "items_found or empty_result"}, "split_strategy": {"type": "string", "description": "Execution strategy for parallel items"}, "total_before_limit": {"type": "number", "description": "Total rows before maxItems cap"}}'::jsonb, '{"item": "Current row in parallel context (access fields: {{item.column_name}})", "index": "Current row index (0-based) in parallel context"}'::jsonb, NULL, '["find_rows acts like Split: each matching row spawns a parallel execution", "In downstream steps, use {{item.column_name}} to access current row fields", "Use {{index}} for the current row''s position (0-based)", "Combine with Aggregate node to collect results after parallel processing", "Use where filter to narrow results; omit for all rows"]'::jsonb, '["workflow_builder(action=''add_node'', type=''find_rows'', label=''Find Active Users'', params={table_id: 42, where: {column: ''status'', operator: ''=='', value: ''active''}, limit: 50}, connect_after=''Start'')", "workflow_builder(action=''add_node'', type=''find_rows'', label=''All Orders'', params={table_id: 15}, connect_after=''Init'')"]'::jsonb, '["find_rows","find","search","query","filter","table","rows","batch","parallel","iterate"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('fork', 'Fork (Parallel Branches)', 'control_flow', 'core', 'Fork: Split into N parallel branches that ALL execute simultaneously. Each branch runs independently. Has ports: branch_0, branch_1, ... Use Merge to wait for all branches to complete. Unlike Decision (one branch), Fork runs ALL branches.', '{"branches": {"type": "array", "example": "[{label: ''Send Email''}, {label: ''Send SMS''}]", "minItems": 2, "required": true, "description": "Array of {label} defining parallel branches. Minimum 2 branches. Also accepts: outputs"}}'::jsonb, '{"branches": {"type": "array", "description": "Array of branch objects, each with index, id, label, and target_count"}, "branch_count": {"type": "number", "description": "Number of parallel branches created"}}'::jsonb, NULL, '{"ports": ["branch_0", "branch_1", "..."], "pattern": "core:label:branch_N"}'::jsonb, '["Operates on STREAMS (paths), not items", "Creates N different paths running different tasks", "Use Merge after to wait for all streams"]'::jsonb, '["workflow_builder(action=''add_node'', type=''fork'', label=''Notify All'', params={branches: [{label: ''Email''}, {label: ''SMS''}, {label: ''Slack''}]}, connect_after=''Get User'')"]'::jsonb, '["fork","parallel","concurrent","split","fan-out","spawn","all-branches"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('form', 'Form Trigger', 'trigger', 'trigger', 'Triggers workflow from a custom form submission with configurable fields.', '{"title": {"type": "string", "required": false, "description": "Form title displayed to users"}, "fields": {"type": "array", "required": false, "description": "[{name, type, label, required, options}]. Types: text, email, textarea, select, checkbox, number, date, datetime, time, file, phone, url, multiselect, checkboxGroup"}, "submit_button_text": {"type": "string", "default": "Submit", "required": false}}'::jsonb, '{"form_data": {"type": "object", "description": "All submitted form fields grouped as object"}, "<field_name>": {"type": "varies", "description": "Each form field is copied to top level. Type depends on field config: text/email/textarea/phone/url/select→string, number→number, checkbox→boolean, date/datetime/time→string, file→file object, multiselect/checkboxGroup→array"}, "submitted_at": {"type": "string", "description": "ISO timestamp of submission"}, "submission_id": {"type": "string", "description": "Unique form submission identifier (UUID)"}, "<field_name>_file_url": {"type": "string", "description": "For file fields: proxy URL to download the file"}, "<field_name>_file_name": {"type": "string", "description": "For file fields: original file name"}, "<field_name>_file_size": {"type": "number", "description": "For file fields: file size in bytes"}, "<field_name>_content_type": {"type": "string", "description": "For file fields: MIME type"}}'::jsonb, NULL, NULL, '["Static outputs: form_data, submitted_at", "Dynamic outputs: each field in fields[] becomes an output", "Type mapping: checkbox→boolean, number→number, date/datetime/time→datetime, file→file, multiselect/checkboxGroup→array, others→text"]'::jsonb, '["workflow_builder(action=''add_node'', type=''form'', label=''Contact Form'', params={title: ''Contact Us'', fields: [{name: ''email'', type: ''email'', label: ''Email'', required: true}, {name: ''subscribe'', type: ''checkbox'', label: ''Subscribe to newsletter''}]})"]'::jsonb, '["form","survey","input","submission","questionnaire","contact","feedback"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('get_rows', 'Get Rows', 'action', 'table', 'Get rows from a table with optional filters.', '{"limit": {"max": 1000, "min": 1, "type": "integer", "default": 100, "required": false}, "where": {"type": "object", "required": false, "description": "{column, operator, value}. Operators: ==, !=, >, <, >=, <=, LIKE, IN"}, "offset": {"type": "integer", "default": 0, "required": false}, "order_by": {"type": "object", "required": false, "description": "{column, direction: ASC|DESC}"}, "table_id": {"type": "integer", "required": true}}'::jsonb, '{"rows": {"type": "array", "description": "Array of row objects"}, "count": {"type": "number", "description": "Number of rows returned"}, "total": {"type": "number", "description": "Total rows available"}, "has_more": {"type": "boolean", "description": "Whether more rows exist beyond limit"}}'::jsonb, NULL, NULL, NULL, '["workflow_builder(action=''add_node'', type=''get_rows'', label=''Active Users'', params={table_id: 123, where: {column: ''status'', operator: ''=='', value: ''active''}, limit: 50}, connect_after=''Trigger'')"]'::jsonb, '["get","read","query","fetch","select","find","search","rows","table"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('guardrail', 'Guardrail', 'ai', 'agent', 'AI-powered content validation with safety rules (PII, toxicity, keywords, compliance).', '{"input": {"type": "string", "required": true, "description": "Content to validate. MUST use {{type:label.output.field}} to reference actual data - the node receives NOTHING automatically. Example: ''{{agent:writer.output.response}}''"}, "label": {"type": "string", "required": true, "description": "Unique label for this node"}, "model": {"type": "string", "default": "claude-sonnet-4-20250514", "required": false}, "rules": {"type": "object", "required": true, "description": "Key=rule ID, Value=description. Ex: {pii: ''Block emails and phones'', toxicity: ''Block offensive content''}"}, "action": {"enum": ["flag", "block", "redact"], "type": "string", "default": "flag", "required": false, "description": "flag=mark but allow, block=prevent, redact=sanitize"}, "prompt": {"type": "string", "required": false, "description": "Custom validation instruction"}, "provider": {"enum": ["openai", "anthropic", "google", "mistral", "deepseek"], "type": "string", "default": "openai", "required": false, "description": "AI provider to use"}, "temperature": {"max": 1, "min": 0, "type": "number", "default": 0.1, "required": false}}'::jsonb, '{"model": {"type": "string", "description": "Model used"}, "passed": {"type": "boolean", "description": "Whether content passed all checks"}, "details": {"type": "object", "description": "Detailed validation information"}, "provider": {"type": "string", "description": "AI provider"}, "sanitized": {"type": "string", "description": "Sanitized version of input (when action=redact)"}, "violations": {"type": "array", "description": "List of rule violations"}, "tokens_used": {"type": "number", "description": "Total tokens consumed"}}'::jsonb, NULL, '{"note": "pass = content passed all checks, fail = content violated rules", "ports": ["pass", "fail"], "pattern": "agent:label:pass, agent:label:fail"}'::jsonb, '["CRITICAL - DATA FLOW: The input parameter MUST reference data from a previous node using {{type:label.output.field}} syntax. Writing just ''Check the content'' gives the node NO data to validate.", "action=flag marks but allows through", "action=block prevents continuation", "action=redact returns sanitized content", "Variable syntax: {{trigger:label.output.field}}, {{mcp:label.output.field}}, {{agent:label.output.response}}, {{core:label.output.field}}", "Typically placed after an agent node to validate its output before proceeding"]'::jsonb, '["workflow_builder(action=''add_node'', type=''guardrail'', label=''Check PII'', params={input: ''{{agent:writer.output.response}}'', rules: {pii: ''Block emails and phones'', toxicity: ''Block offensive content''}, action: ''redact''}, connect_after=''Writer'')"]'::jsonb, '["guardrail","validation","safety","pii","toxicity","compliance","moderation"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('http_request', 'HTTP Request', 'control_flow', 'core', 'HTTP Request: Make HTTP API calls to external services. Supports all HTTP methods, authentication (bearer, basic, API key), query parameters, headers, and request body. Use this when no MCP tool exists for the API you need.', '{"url": {"type": "string", "example": "https://api.example.com/users/{{trigger:form.output.user_id}}", "required": true, "description": "Full URL to call. Supports SpEL expressions. Also accepts: endpoint, uri"}, "body": {"type": "any", "required": false, "description": "Request body content"}, "method": {"enum": ["GET", "POST", "PUT", "PATCH", "DELETE"], "type": "string", "default": "GET", "required": false, "description": "HTTP method"}, "headers": {"type": "array", "required": false, "description": "Custom headers as [{key, value}]"}, "timeout": {"max": 300000, "min": 1000, "type": "integer", "default": 30000, "required": false, "description": "Timeout in ms (1000-300000)"}, "authType": {"enum": ["none", "bearer", "basic", "apikey"], "type": "string", "default": "none", "required": false, "description": "Authentication type. Also accepts: auth_type"}, "bodyType": {"enum": ["json", "form", "raw"], "type": "string", "default": "json", "required": false, "description": "Body format. Also accepts: body_type"}, "authConfig": {"type": "object", "required": false, "description": "Auth configuration. Also accepts: auth_config. For bearer: {token}. For basic: {username, password}. For apikey: {headerName, apiKey}"}, "queryParams": {"type": "array", "required": false, "description": "Query parameters as [{key, value}]. Also accepts: query_params"}}'::jsonb, '{"data": {"type": "any", "description": "Response body (parsed JSON or raw text)"}, "error": {"type": "string", "description": "Error message when request failed (null on success)"}, "status": {"type": "number", "description": "HTTP status code (e.g. 200, 404, 500)"}, "headers": {"type": "object", "description": "Response headers as key-value pairs"}, "success": {"type": "boolean", "description": "Whether the request completed without exceptions"}, "statusText": {"type": "string", "description": "HTTP status text (e.g. 200 OK, 404 Not Found)"}}'::jsonb, NULL, NULL, NULL, '["workflow_builder(action=''add_node'', type=''http_request'', label=''Get User'', params={url: ''https://api.example.com/users/{{trigger:form.output.user_id}}''}, connect_after=''Form'')", "workflow_builder(action=''add_node'', type=''http_request'', label=''Create Order'', params={method: ''POST'', url: ''https://api.example.com/orders'', authType: ''bearer'', authConfig: {token: ''{{mcp:auth.output.token}}''}, body: {product: ''{{trigger:form.output.product}}''}}, connect_after=''Auth'')"]'::jsonb, '["http","request","api","rest","fetch","get","post","put","delete","external","endpoint","call","web","service"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('insert_row', 'Insert Row', 'action', 'table', 'Insert a new row into a table.', '{"columns": {"type": "object", "required": true, "description": "{column: value or expression}"}, "table_id": {"type": "integer", "required": true}}'::jsonb, '{"row_id": {"type": "string", "description": "ID of the inserted row"}, "created_at": {"type": "string", "description": "ISO timestamp of insertion"}, "inserted_values": {"type": "object", "description": "Map of column names to inserted values"}}'::jsonb, NULL, NULL, NULL, '["workflow_builder(action=''add_node'', type=''insert_row'', label=''Save Contact'', params={table_id: 123, columns: {name: ''{{trigger:form.output.name}}'', email: ''{{trigger:form.output.email}}''}}, connect_after=''Form'')"]'::jsonb, '["insert","create","save","write","add","row","database","table"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('interface', 'Interface', 'node', 'interface', 'Interface node: visual HTML template connected to a workflow. ALWAYS provide all 3 templates when creating: html_template, css_template, js_template. Use CSS classes (no inline style="..."). Use js_template for conditional display and dynamic behavior. ONLY {{variable}} and {{variable|default}} are supported - NEVER use {{#if}}, {{#each}}, {{else}}, {{/if}} (NOT Handlebars). EXECUTION: Registers a non-blocking INTERFACE_SIGNAL. Workflow COMPLETES normally. User interacts later. Use __continue action to resolve the signal and resume DAG execution past this node. For display-only interfaces, omit action_mapping - the interface still registers a signal for lifecycle tracking. 3 USAGE PATTERNS: (A) DISPLAY: variable_mapping binds template variables to workflow data. No action_mapping needed. (B) APPLICATION: action_mapping binds forms/buttons to triggers → user submits → workflow runs → results displayed (loop). (C) MULTI-PAGE APP: multiple interface nodes + navigate actions to switch between pages. Create the template first with interface(action=''create'') using generic {{variable|default}} syntax.', E'{"showPreview": {"type": "boolean", "default": true, "required": false, "description": "Show live preview on the workflow builder canvas"}, "interface_id": {"type": "uuid", "required": true, "description": "UUID from interface(action=''create'')"}, "action_mapping": {"type": "object", "required": false, "description": "Binds HTML elements to workflow triggers or navigation via CSS selectors. Format: {\\"#css-selector\\": \\"target\\"}. The CSS selector MUST match an HTML element id (e.g. #search-form matches <form id=\\"search-form\\">). Targets: trigger:label:submit (form - captures all <input name=...> fields), trigger:label:click (button - fires trigger, no data), trigger:label:message (chat input), interface:label:navigate (page switch, frontend-only), __continue (resolve signal, resume DAG), __pagination:prev/__pagination:next (browse results). SAME-DAG RULE: All trigger references in action_mapping MUST belong to the SAME DAG as the interface. For multiple actions (search, delete, refresh), create multiple triggers within the same DAG. Referenced triggers MUST already exist in the workflow."}, "isEntryInterface": {"type": "boolean", "default": false, "required": false, "description": "Mark as primary interface in multi-interface workflows (shown first in application view). At least one interface must be entry."}, "variable_mapping": {"type": "object", "required": false, "description": "DISPLAY: Map template variables to workflow data. {\\"title\\": \\"{{mcp:fetch.output.name}}\\"}"}}'::jsonb, '{"node_type": "INTERFACE", "interface_id": "UUID of the interface entity", "spel_pattern": "{{interface:label.output.action_name.field_name}} - e.g. {{interface:my_form.output.submit.email}}", "output.{action_name}": "Object containing user-submitted form data plus fired_at timestamp (after user fires an action). Access downstream via {{interface:label.output.action_name.field_name}}", "output.{action_name}.fired_at": "ISO timestamp when the action was fired"}'::jsonb, NULL, NULL, E'["BLOCKING vs AUTO-ADVANCE: If action_mapping contains __continue, the interface is BLOCKING - workflow pauses (RUNNING) until user clicks the __continue button, like USER_APPROVAL. If NO __continue, the interface is AUTO-ADVANCE - node completes immediately (SUCCESS), successors execute, and the interface stays clickable for triggering actions/spawns.", "BLOCKING INTERFACE (__continue): Workflow reaches interface → pauses (epoch stays open) → user interacts → clicks __continue → signal resolves → workflow resumes to next node. Use for wizards, forms that must complete before proceeding.", "AUTO-ADVANCE INTERFACE (no __continue): Workflow reaches interface → completes immediately → successors execute → interface stays displayed and clickable. Buttons fire triggers (new epochs/spawns). Use for dashboards, interactive apps.", "ACTION MAPPING WIRING: CSS selector in action_mapping must match an HTML element id. All referenced triggers MUST be in the SAME DAG as the interface. Example: HTML has <form id=\\"search-form\\"><input name=\\"query\\"/></form> and <button id=\\"delete-btn\\">Delete</button>. action_mapping: {\\"#search-form\\": \\"trigger:search:submit\\", \\"#delete-btn\\": \\"trigger:delete:click\\"}. Both trigger:search and trigger:delete must be in the same DAG as this interface.", "SAME-DAG INTERACTIVE APP: An interface belongs to ONE DAG and can only fire triggers within that same DAG. For interactive apps: create one DAG with multiple triggers (search, delete, refresh) + processing steps + interface. action_mapping binds HTML elements to the DAG own triggers. Multiple buttons on one page = multiple triggers in ONE DAG.", "DISPLAY MODE: variable_mapping only (no action_mapping): binds {{title|default}} to {{mcp:step.output.field}}. Interface shows workflow output data, no user interaction needed. Node auto-advances.", "MULTI-PAGE APP: Multiple interface nodes + navigate actions. Example: #go-settings → interface:settings_page:navigate switches the displayed interface (frontend-only, no API call).", "__CONTINUE ACTION: Add __continue as action_mapping target on a Done/Continue button. Makes the interface BLOCKING. When user clicks it, the signal is resolved and DAG execution resumes from this node to its successors.", "EDGE FORMAT: Interfaces use interface: prefix. { from: trigger:start, to: interface:customer_form }. No ports (interfaces are linear, not branching). Plan array: interfaces[] (separate from triggers/mcps/cores/agents).", "INTERFACE OUTPUTS: When blocking (__continue), action data is persisted and accessible downstream via SpEL: {{interface:label.output.action_name.field_name}}. Example: {{interface:my_form.output.submit.email}} returns the email submitted via the form."]'::jsonb, '["workflow_builder(action=''add_node'', type=''interface'', label=''Dashboard'', params={interface_id: ''<uuid>'', mode: ''passage'', variable_mapping: {''title'': ''{{mcp:fetch.output.name}}'', ''status'': ''{{mcp:fetch.output.status}}''}}, connect_after=''FetchData'')", "workflow_builder(action=''add_node'', type=''interface'', label=''Contact Form'', params={interface_id: ''<uuid>'', mode: ''on_event'', variable_mapping: {''name'': ''{{mcp:get_user.output.name}}''}, action_mapping: {''#contact-form'': ''trigger:contact_form:submit'', ''#done-btn'': ''__continue''}}, connect_after=''GetUser'')", "workflow_builder(action=''add_node'', type=''interface'', label=''Order Dashboard'', params={interface_id: ''<uuid>'', mode: ''on_event'', action_mapping: {''#search-form'': ''trigger:search:submit'', ''#delete-btn'': ''trigger:delete:click'', ''#refresh-btn'': ''trigger:refresh:click''}, isEntryInterface: true}, connect_after=''Init'')"]'::jsonb, '["interface","html","display","template","card","ui","visual","application","app","form","submit","navigate","page","interactive","afficher","formulaire","application","page","navigation"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('limit', 'Limit', 'data_manipulation', 'core', 'Passes through only the first or last N items from the input, with optional offset for pagination. Use to take top/bottom results or paginate data.', '{"from": {"type": "string", "default": "first", "example": "first", "required": false, "description": "Take items from ''first'' or ''last''."}, "count": {"type": "integer", "default": 10, "example": 5, "required": false, "description": "Number of items to keep."}, "offset": {"type": "integer", "default": 0, "example": 0, "required": false, "description": "Number of items to skip before applying the limit."}}'::jsonb, '{"count": {"type": "number", "description": "Number of items in the result"}, "items": {"type": "array", "description": "Array of items after applying count and offset"}, "config": {"type": "object", "description": "Limit configuration applied (count, from, offset)"}, "original_count": {"type": "number", "description": "Number of items before limiting"}}'::jsonb, NULL, NULL, '["Limit takes the first or last N items from input data", "Use offset to skip items before applying the limit (pagination)", "No ports - single output edge like transform/wait", "Access outputs: {{core:label.output.items}}, {{core:label.output.count}}", "Combine with Sort to get top/bottom N by a field"]'::jsonb, '["workflow_builder(action=''add_node'', type=''limit'', label=''Top 5'', params={count: 5, from: ''first''}, connect_after=''Sort Results'')", "workflow_builder(action=''add_node'', type=''limit'', label=''Last 3'', params={count: 3, from: ''last''}, connect_after=''Fetch Data'')", "workflow_builder(action=''add_node'', type=''limit'', label=''Page 2'', params={count: 10, from: ''first'', offset: 10}, connect_after=''Get All Items'')"]'::jsonb, '["limit","top","bottom","first","last","take","head","tail","paginate","offset","skip","slice","truncate"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('loop', 'Loop', 'control_flow', 'core', 'While loop that repeatedly executes a body branch while a condition is true. Has two ports: body (executes each iteration) and exit (continues after loop ends). Supports max iteration limit for safety.', '{"condition": {"type": "string", "example": "{{mcp:api.output.has_more}} == true", "required": false, "description": "SpEL expression evaluated each iteration. Loop enters body while true. If omitted, always enters body (use max_iterations to limit)."}, "max_iterations": {"type": "integer", "default": 10, "example": 5, "required": false, "description": "Maximum number of iterations (safety limit). Range: 1-10000."}}'::jsonb, '{"iteration": {"type": "number", "description": "Current iteration number (0 on first entry)"}, "enter_body": {"type": "boolean", "description": "Whether the loop body should be entered"}, "terminated": {"type": "boolean", "description": "Whether the loop condition was false on entry"}, "maxIterations": {"type": "number", "description": "Configured max iterations"}, "selected_path": {"type": "string", "description": "body or exit"}}'::jsonb, NULL, '{"body": "core:label:body → first body node (executes each iteration)", "exit": "core:label:exit → node after loop ends", "ports": ["body", "iterate", "exit"], "iterate": "core:label:iterate → back-edge from last body step to loop (re-evaluates condition)", "pattern": "core:label:body, core:label:iterate, core:label:exit"}'::jsonb, '["Loop has 2 ports: body (repeated) and exit (after loop ends)", "Connect body port to the step(s) that execute each iteration", "Connect exit port to the step that runs after the loop finishes", "The last step in the body branch must connect back to the loop node to create the cycle", "Use max_iterations to prevent infinite loops", "Access iteration count: {{core:label.output.iteration}}"]'::jsonb, '["workflow_builder(action=''add_node'', type=''loop'', label=''Retry Loop'', params={condition: ''{{mcp:api.output.has_more}} == true'', max_iterations: 5}, connect_after=''Fetch Page'')", "workflow_builder(action=''connect'', from=''core:retry_loop:body'', to=''Process Item'')", "workflow_builder(action=''connect'', from=''core:retry_loop:exit'', to=''Done'')"]'::jsonb, '["loop","while","for","repeat","iterate","cycle","retry","condition","body","exit"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('manual', 'Manual Trigger', 'trigger', 'trigger', 'Triggers workflow manually via Run button.', '{}'::jsonb, '{"triggered_at": {"type": "string", "description": "ISO timestamp when workflow was triggered"}, "triggered_by": {"type": "string", "description": "User ID who triggered the workflow"}}'::jsonb, NULL, NULL, '["Simplest trigger for testing or on-demand execution"]'::jsonb, '["workflow_builder(action=''add_node'', type=''manual'', label=''Run Report'')"]'::jsonb, '["manual","button","run","start","click","human"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('mcp', 'MCP Tool', 'action', 'mcp', 'MCP tools are external integrations. Use catalog_search to find tool UUIDs, then use the UUID directly as the type parameter.', '{"NOTE": {"type": "string", "description": "MCP tools use the tool UUID directly as type. Params are the tool inputs (flat, not nested)."}, "<tool_param>": {"type": "varies", "description": "Tool-specific parameters from catalog_search schema"}}'::jsonb, '{"<tool_output>": {"type": "varies", "description": "Tool-specific outputs"}}'::jsonb, NULL, NULL, '["1. Use catalog_search(query=''...'') to find tool UUID and schema", "2. Use type=''<tool-uuid>'' directly (NOT type=''mcp'')", "3. Params are flat tool inputs (no nested id/inputs)"]'::jsonb, E'["# Step 1: Find tool\\ncatalog_search(query=''gmail send email'')\\n# Returns: {uuid: ''abc-123'', inputSchema: {to: string, subject: string, body: string}}\\n\\n# Step 2: Add node with tool UUID as type\\nworkflow_builder(action=''add_node'', type=''abc-123'', label=''Send Email'', params={to: ''{{trigger:form.output.email}}'', subject: ''Welcome!'', body: ''Hello {{trigger:form.output.name}}''}, connect_after=''Form'')"]'::jsonb, '["mcp","step","catalog","external","api","integration","tool","service","gmail","slack"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('merge', 'Merge (Wait for All)', 'control_flow', 'core', 'Merge: Wait for ALL incoming branches to complete (SYNCHRONIZATION ONLY). Counterpart to Fork: Fork creates N branches, Merge waits for all N. No data transformation - just synchronization. Waits for all predecessors to be COMPLETED or SKIPPED before continuing.', '{"mergeInputs": {"type": "array", "required": false, "description": "Optional: [{label}] to name the expected inputs. Also accepts: inputs. Usually not needed - merge auto-detects predecessors from edges"}}'::jsonb, '{"sources": {"type": "object", "description": "Outputs keyed by source node ID"}, "strategy": {"type": "string", "description": "Merge strategy used (QUEUE_1_TO_1, COMBINE_ALL, FIRST_AVAILABLE)"}, "item_count": {"type": "number", "description": "Number of items in merged_items"}, "merged_items": {"type": "array", "description": "Array of merged items from all sources"}, "source_count": {"type": "number", "description": "Number of source branches"}, "success_count": {"type": "number", "description": "Number of sources that completed successfully"}}'::jsonb, NULL, NULL, '["Has N INPUT BRANCHES (not N item contexts like Aggregate)", "Merge vs Aggregate: Merge=N branches, Aggregate=1 branch (N items)", "No data transformation, just synchronization", "Use after Fork to wait for parallel branches"]'::jsonb, '["workflow_builder(action=''add_node'', type=''merge'', label=''Wait All'', connect_after=''Email'')", "workflow_builder(action=''add_node'', type=''merge'', label=''Sync Point'', params={mergeInputs: [{label: ''Email''}, {label: ''SMS''}]}, connect_after=''Email'')"]'::jsonb, '["merge","join","sync","combine","wait-all","barrier","converge"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('option', 'Option', 'core', 'core', 'Evaluates multiple conditions and routes to the first matching choice (like an enhanced decision node with N branches).', '{"choices": {"type": "array", "required": true, "description": "Array of choice objects, each with id, label, and condition expression"}, "fallback": {"type": "string", "description": "Fallback behavior when no choice matches (skip or error)"}}'::jsonb, '{"evaluations": {"type": "array", "description": "Detailed evaluation results per choice"}, "selected_label": {"type": "string", "description": "Label of the selected choice"}, "selected_choice": {"type": "string", "description": "ID of the choice that matched"}, "skipped_choices": {"type": "array", "description": "IDs of skipped choices"}, "condition_result": {"type": "boolean", "description": "Whether any choice matched"}, "condition_expression": {"type": "string", "description": "Expression of the selected choice"}, "selected_choice_index": {"type": "number", "description": "Index of the selected choice"}, "skipped_choice_labels": {"type": "array", "description": "Labels of skipped choices"}}'::jsonb, NULL, '{"note": "N = array index (0-based). Creates 1 port per choice + optional fallback.", "example": "choices: [A, B, C] → choice_0, choice_1, choice_2, fallback", "pattern": "core:label:choice_N"}'::jsonb, NULL, NULL, NULL, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('remove_duplicates', 'Remove Duplicates', 'utility', 'core', 'Remove duplicate items from an array based on a key field.', NULL, '{"items": {"type": "array", "description": "Deduplicated items"}, "removed_count": {"type": "number", "description": "Number of duplicates removed"}, "original_count": {"type": "number", "description": "Count before deduplication"}, "deduplicated_count": {"type": "number", "description": "Count after deduplication"}}'::jsonb, NULL, NULL, NULL, NULL, NULL, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('respond_to_webhook', 'Respond to Webhook', 'utility', 'core', 'Controls the HTTP response returned to a synchronous webhook caller. When a webhook is called with sync=true, this node resolves the pending HTTP response with a custom status code, body, content type, and headers. If no pending webhook exists (manual trigger or async webhook), the node succeeds silently with responded=false.', E'{"body": {"type": "string", "required": false, "description": "Response body as a string. Supports SpEL expressions to include workflow data (e.g., {{mcp:step.output.result}})."}, "headers": {"type": "object", "default": {}, "required": false, "description": "Custom response headers as key-value pairs (e.g., {\\"X-Request-Id\\": \\"abc\\"})."}, "statusCode": {"type": "integer", "default": 200, "required": false, "description": "HTTP status code to return (e.g., 200, 201, 400, 404, 500)."}, "contentType": {"type": "string", "default": "application/json", "required": false, "description": "Content-Type header value (e.g., application/json, text/html, text/plain)."}}'::jsonb, '{"responded": {"type": "boolean", "description": "Whether the webhook response was sent"}, "statusCode": {"type": "number", "description": "HTTP status code returned"}, "contentType": {"type": "string", "description": "Response content type"}}'::jsonb, NULL, NULL, '["Only works when the webhook is called with ?sync=true query parameter", "If no pending webhook exists, the node succeeds with responded=false (safe for manual triggers)", "The body supports SpEL expressions: {{mcp:step.output.data}} resolves to step output", "Place this node after your processing steps but before the workflow ends", "Only one RespondToWebhook node should resolve per webhook call", "Custom headers are merged with the Content-Type header", "Access results: {{core:label.output.responded}}, {{core:label.output.statusCode}}"]'::jsonb, E'["workflow_builder(action=''add_node'', type=''respond_to_webhook'', label=''Send Response'', params={statusCode: 200, body: ''{{mcp:process.output.result}}'', contentType: ''application/json''}, connect_after=''Process Data'')", "workflow_builder(action=''add_node'', type=''respond_to_webhook'', label=''Error Response'', params={statusCode: 400, body: ''{\\"error\\": \\"Invalid input\\"}'', contentType: ''application/json''}, connect_after=''Validate Input'')", "workflow_builder(action=''add_node'', type=''respond_to_webhook'', label=''HTML Response'', params={statusCode: 200, body: ''<h1>Success</h1>'', contentType: ''text/html'', headers: {\\"X-Custom\\": \\"value\\"}}, connect_after=''Generate HTML'')"]'::jsonb, '["respond","webhook","response","http","reply","sync","return","status","body","headers","custom response"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('response', 'Response', 'control_flow', 'core', 'Sends a message back to the user in the SAME chat conversation. ONLY useful for chat-triggered workflows (trigger type = chat). If no chat trigger exists, the message will only appear in execution logs.', '{"message": {"type": "string", "required": true, "description": "Message content (supports {{variable}} expressions to include dynamic data from previous steps)"}}'::jsonb, '{"message": {"type": "string", "description": "The resolved message that was sent"}, "sent_at": {"type": "string", "description": "ISO timestamp when message was sent"}, "message_id": {"type": "string", "description": "Unique message identifier"}}'::jsonb, NULL, NULL, '["ONLY sends visible messages when workflow has a chat trigger", "Without chat trigger, message is logged but not displayed to any user", "Use {{variable}} syntax to include dynamic data in the message"]'::jsonb, '["workflow_builder(action=''add_node'', type=''response'', label=''Reply'', params={message: ''Your order {{mcp:create_order.output.id}} has been created!'', format: ''markdown''}, connect_after=''Create Order'')"]'::jsonb, '["response","message","reply","send","notify","chat","output"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('rss', 'RSS', 'data_manipulation', 'core', 'Fetches and parses RSS/Atom feeds from URLs. Automatically detects feed format (RSS 2.0 or Atom) and extracts structured data including channel metadata and individual feed items. Each item includes title, link, description, publication date, author, categories, and guid. Useful for monitoring news feeds, aggregating blog posts, or integrating with content syndication workflows.', '{"url": {"type": "string", "required": true, "description": "URL of the RSS or Atom feed to fetch. Supports SpEL templates like {{trigger:start.output.feedUrl}} or {{mcp:step.output.url}}."}, "maxItems": {"type": "integer", "default": 20, "required": false, "description": "Maximum number of feed items to return. Defaults to 20 if not specified or if set to 0 or negative."}}'::jsonb, '{"items": {"type": "array", "description": "List of feed items, each with title, link, description, pubDate, author, categories, and guid"}, "channel": {"type": "object", "description": "Feed-level metadata: title, description, link, language, lastBuildDate"}, "feedUrl": {"type": "string", "description": "The URL that was fetched"}, "success": {"type": "boolean", "description": "Whether the fetch and parse completed successfully"}, "itemCount": {"type": "number", "description": "Number of items returned after maxItems limiting"}, "feedFormat": {"type": "string", "description": "Detected feed format: rss or atom"}}'::jsonb, NULL, NULL, '["Automatically detects RSS 2.0 (<rss>) vs Atom (<feed>) format", "RSS items are extracted from <item> elements, Atom entries from <entry> elements", "Channel/feed-level metadata is always included (title, description, link, language, lastBuildDate)", "maxItems limits the number of items returned - items beyond the limit are discarded", "Access feed items: {{core:label.output.items}} - returns a list of item maps", "Access single item field: {{core:label.output.items[0].title}}", "Access channel info: {{core:label.output.channel.title}}", "Access item count: {{core:label.output.itemCount}}", "Combine with Split node to process each feed item individually", "XXE protection is enabled by default (external entities are blocked)"]'::jsonb, '["workflow_builder(action=''add_node'', type=''rss'', label=''Fetch News'', params={url: ''https://news.example.com/rss'', maxItems: 10}, connect_after=''Start'')", "workflow_builder(action=''add_node'', type=''rss'', label=''Read Blog Feed'', params={url: ''{{trigger:start.output.feedUrl}}'', maxItems: 5}, connect_after=''Webhook'')", "workflow_builder(action=''add_node'', type=''rss'', label=''Monitor Updates'', params={url: ''https://blog.example.com/atom.xml'', maxItems: 20}, connect_after=''Schedule'')"]'::jsonb, '["rss","atom","feed","news","blog","syndication","xml","subscribe","monitor","aggregate","content"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('schedule', 'Schedule Trigger', 'trigger', 'trigger', 'Triggers workflow on a schedule using cron expressions. Minimum frequency: every minute.', '{"enabled": {"type": "boolean", "default": true, "required": false}, "schedule": {"type": "string", "required": true, "description": "Standard 5-field cron expression: minute hour day-of-month month day-of-week. Examples: ''0 9 * * *'' (daily at 9AM), ''*/5 * * * *'' (every 5 min), ''* * * * *'' (every minute = minimum)"}, "timezone": {"type": "string", "default": "UTC", "required": false}}'::jsonb, '{"triggered_at": {"type": "string", "description": "ISO timestamp of trigger"}, "next_execution": {"type": "string", "description": "ISO timestamp of next scheduled execution"}, "execution_count": {"type": "number", "description": "Current execution number (1-based)"}}'::jsonb, NULL, NULL, '["Cron format: minute hour day-of-month month day-of-week", "Minimum frequency: every minute (* * * * *)", "Common: */5 * * * * (every 5 min), 0 * * * * (hourly), 0 9 * * * (daily 9AM), 0 9 * * 1-5 (weekdays 9AM)"]'::jsonb, '["workflow_builder(action=''add_node'', type=''schedule'', label=''Daily Report'', params={schedule: ''0 9 * * *'', timezone: ''America/New_York''})", "workflow_builder(action=''add_node'', type=''schedule'', label=''Every 5 Minutes'', params={schedule: ''*/5 * * * *''})"]'::jsonb, '["schedule","cron","timer","interval","periodic","recurring","daily","hourly"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('send_email', 'Send Email (SMTP)', 'utility', 'core', 'Send emails via SMTP using user-provided credentials. Supports plain text and HTML, multiple recipients (To, CC, BCC), and dynamic SpEL expressions in all fields.', '{"body": {"type": "string", "required": true, "description": "Email body content. Supports SpEL expressions."}, "isHtml": {"type": "boolean", "default": false, "required": false, "description": "Whether the body is HTML content."}, "ccEmail": {"type": "string", "required": false, "description": "CC email address(es), comma-separated."}, "subject": {"type": "string", "required": true, "description": "Email subject line. Supports SpEL expressions."}, "toEmail": {"type": "string", "required": true, "description": "Recipient email address(es), comma-separated for multiple."}, "bccEmail": {"type": "string", "required": false, "description": "BCC email address(es), comma-separated."}, "smtpHost": {"type": "string", "required": true, "description": "SMTP server hostname (e.g., smtp.gmail.com)."}, "smtpPort": {"type": "integer", "required": true, "description": "SMTP port (typically 587 for TLS, 465 for SSL)."}, "smtpPassword": {"type": "string", "required": true, "description": "SMTP password or app-specific password."}, "smtpUsername": {"type": "string", "required": true, "description": "SMTP username for authentication."}}'::jsonb, '{"sent": {"type": "boolean", "description": "Whether the email was successfully sent"}, "isHtml": {"type": "boolean", "description": "Whether the body was HTML"}, "subject": {"type": "string", "description": "Email subject"}, "success": {"type": "boolean", "description": "Whether the operation succeeded"}, "messageId": {"type": "string", "description": "SMTP message ID"}, "recipients": {"type": "string", "description": "Comma-separated recipient emails"}}'::jsonb, NULL, NULL, '["Requires valid SMTP credentials (host, port, username, password)", "For Gmail, use an App Password (not regular password)", "All fields support SpEL expressions for dynamic content", "Multiple recipients can be comma-separated in toEmail, ccEmail, bccEmail", "Set isHtml=true to send HTML-formatted emails"]'::jsonb, '["workflow_builder(action=''add_node'', type=''send_email'', label=''Send Notification'', params={smtpHost: ''smtp.gmail.com'', smtpPort: 587, smtpUsername: ''user@example.com'', smtpPassword: ''app-password'', toEmail: ''{{trigger:form.output.email}}'', subject: ''Order Confirmation'', body: ''Your order has been confirmed.'', isHtml: false})"]'::jsonb, '["email","smtp","send","mail","notification","message","gmail","outlook"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('sort', 'Sort', 'utility', 'core', 'Sort items in an array by one or more fields.', NULL, '{"count": {"type": "number", "description": "Number of items sorted"}, "sorted_items": {"type": "array", "description": "Array of sorted items"}}'::jsonb, NULL, NULL, NULL, NULL, NULL, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('split', 'Split', 'control_flow', 'core', 'Split: 1 list → N parallel item contexts. Takes a list and creates N parallel executions, one per item. TWO DATA LAYERS: (1) PERSISTED OUTPUTS (saved in DB): items, item_count, split_id, spawn_reason, terminated. (2) RUNTIME CONTEXT (available ONLY inside body nodes): current_item = the specific item for each parallel branch, current_index = 0-based index. Body nodes use {{core:<label>.output.current_item}} and {{core:<label>.output.current_index}} to access per-item data. Shorthand: {{item}} and {{index}} also work inside body. NOT for branching (use Fork). Counterpart: Aggregate collects the N results back into 1.', '{"items": {"type": "string", "example": "{{mcp:get_users.output.users}}", "required": true, "description": "SpEL expression returning a list to iterate over. Aliases accepted: list, input, array, data, collection, source"}, "maxItems": {"max": 1000, "min": 1, "type": "integer", "default": 100, "required": false, "description": "Maximum items to process (default: 100, max: 1000). Also accepts: max_items"}}'::jsonb, '{"items": {"type": "array", "description": "Array of items being split"}, "split_id": {"type": "string", "description": "Node ID of the split"}, "item_count": {"type": "number", "description": "Number of items being split"}, "terminated": {"type": "boolean", "description": "Whether split has terminated"}, "current_item": {"type": "any", "description": "Current item in parallel branch (runtime context, available to body nodes only)"}, "spawn_reason": {"type": "string", "description": "Reason for spawning"}, "current_index": {"type": "number", "description": "0-based index of current item (runtime context, available to body nodes only)"}}'::jsonb, '{"items": "{{core:<label>.output.items}} - Full items list (PERSISTED)", "item_count": "{{core:<label>.output.item_count}} - Total count (PERSISTED)", "current_item": "{{core:<label>.output.current_item}} - The current item object (RUNTIME, body nodes only). Access fields: {{core:<label>.output.current_item.email}}", "current_index": "{{core:<label>.output.current_index}} - 0-based index (RUNTIME, body nodes only)", "item_shorthand": "{{item}} - Shorthand for current_item (inside body only)", "index_shorthand": "{{index}} - Shorthand for current_index (inside body only)"}'::jsonb, NULL, '["TWO LAYERS: Split has 2 data layers: (1) PERSISTED outputs saved in DB (items, item_count, split_id, spawn_reason, terminated), (2) RUNTIME context for body nodes only (current_item, current_index). Body nodes access per-item data via current_item.", "BODY SYNTAX: Inside body nodes: {{core:<label>.output.current_item}} for the item, {{core:<label>.output.current_index}} for index. Shorthands: {{item}} and {{index}}", "EXAMPLE: Split label=Process Users, items={{mcp:get_users.output.users}} → body node uses {{core:process_users.output.current_item.email}} to get each user email", "AGGREGATE: Use Aggregate after Split to collect body results back into arrays", "NOT FORK: Split = 1 list → N parallel SAME task. Fork = N DIFFERENT parallel tasks"]'::jsonb, '["workflow_builder(action=''add_node'', type=''split'', label=''Process Users'', params={items: ''{{mcp:get_users.output.users}}''}, connect_after=''Get Users'')", "workflow_builder(action=''add_node'', type=''split'', label=''Send Emails'', params={items: ''{{trigger:form.output.recipients}}'', maxItems: 50}, connect_after=''Form'')"]'::jsonb, '["split","parallel","map","iterate","each","array","list","items"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('stop', 'Stop', 'control_flow', 'core', 'Stop: Terminate workflow execution immediately. Can set a reason and final status. Use for error handling, early exit, or explicit workflow completion.', '{"reason": {"type": "string", "example": "Invalid input received", "required": false, "description": "Why the workflow is stopping"}, "status": {"enum": ["stopped", "cancelled", "failed", "completed"], "type": "string", "default": "stopped", "required": false, "description": "Final workflow status"}}'::jsonb, '{"reason": {"type": "string", "description": "Stop reason text from node configuration"}, "status": {"type": "string", "description": "Status of the stop"}, "stopped_at": {"type": "string", "description": "ISO timestamp when workflow was stopped"}}'::jsonb, NULL, NULL, '["Terminal node - no outgoing edges", "Use for early exit on validation failure or error"]'::jsonb, '["workflow_builder(action=''add_node'', type=''stop'', label=''Error Exit'', params={reason: ''Validation failed'', status: ''failed''}, connect_after=''Check Valid'')", "workflow_builder(action=''add_node'', type=''stop'', label=''Done'', params={status: ''completed''}, connect_after=''Final Step'')"]'::jsonb, '["stop","halt","abort","terminate","end","exit","cancel"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('sub_workflow', 'Sub-Workflow', 'control_flow', 'core', 'Executes another workflow as a function call (ephemeral run pattern). Loads the target workflow by ID, passes input data via inputMapping, runs it synchronously with a configurable timeout, and returns the sub-workflow''s outputs. Includes anti-recursion protection via a configurable maxDepth limit. Useful for composing complex workflows from reusable building blocks.', '{"maxDepth": {"type": "integer", "default": 5, "required": false, "description": "Maximum recursion depth to prevent infinite loops when sub-workflows call other sub-workflows. Capped at 10."}, "workflowId": {"type": "string", "required": true, "description": "UUID of the workflow to execute. Can be a SpEL expression like {{trigger.output.workflowId}}."}, "inputMapping": {"type": "string", "required": false, "description": "SpEL expression for input data to pass to the sub-workflow. If omitted, the current trigger data is passed. Example: {{mcp:fetch_data.output.result}}."}, "timeoutSeconds": {"type": "integer", "default": 300, "required": false, "description": "Maximum time in seconds to wait for the sub-workflow to complete. Range: 1-3600."}}'::jsonb, '{"result": {"type": "object", "description": "Output from the sub-workflow execution"}, "success": {"type": "boolean", "description": "Whether the sub-workflow completed successfully"}, "subRunId": {"type": "string", "description": "Run ID of the sub-workflow execution"}, "subWorkflowId": {"type": "string", "description": "ID of the sub-workflow that was executed"}}'::jsonb, NULL, NULL, '["Executes the target workflow as an ephemeral (one-shot) run", "Input data is passed to the sub-workflow as trigger data", "The node waits synchronously for the sub-workflow to complete (up to timeoutSeconds)", "Anti-recursion: tracks call depth and fails if maxDepth is exceeded", "Sub-workflow failure propagates as this node''s failure", "Access sub-workflow results: {{core:label.output.result.mcp:step_key.output.field}}", "The sub-workflow runs with the same tenantId as the parent workflow"]'::jsonb, '["workflow_builder(action=''add_node'', type=''sub_workflow'', label=''Call Enrichment'', params={workflowId: ''abc-123-def'', inputMapping: ''{{mcp:fetch_user.output.result}}'', timeoutSeconds: 120}, connect_after=''Fetch User'')", "workflow_builder(action=''add_node'', type=''sub_workflow'', label=''Run Validation'', params={workflowId: ''{{trigger.output.validation_workflow_id}}'', timeoutSeconds: 60, maxDepth: 3}, connect_after=''Start'')", "workflow_builder(action=''add_node'', type=''sub_workflow'', label=''Process Batch'', params={workflowId: ''batch-processor-id'', inputMapping: ''{{core:split.output.item}}'', timeoutSeconds: 300}, connect_after=''Split Items'')"]'::jsonb, '["sub-workflow","sub_workflow","call","invoke","function","compose","reuse","nested","child","ephemeral","delegation"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('summarize', 'Summarize', 'data_manipulation', 'core', 'Aggregates data using operations like sum, avg, count, min, max, countDistinct, concatenate. Supports optional group-by fields to produce per-group statistics. When no group-by is specified, aggregates across all items into a single result.', '{"groupBy": {"type": "array", "items": "string", "default": "[]", "required": false, "description": "List of field names to group by. When empty, all items are aggregated into a single group."}, "aggregations": {"type": "array", "items": {"alias": "string (output key name, defaults to operation_field)", "field": "string (nullable for count)", "operation": "string (sum|avg|count|min|max|countDistinct|concatenate)"}, "required": true, "description": "List of aggregation operations. Each has: field (column name, null for count), operation (aggregation type), alias (output field name)."}}'::jsonb, '{"groups": {"type": "array", "description": "Grouped summary results"}, "total_items": {"type": "number", "description": "Total items processed"}, "total_groups": {"type": "number", "description": "Number of groups created"}, "aggregation_count": {"type": "number", "description": "Number of aggregation operations applied"}}'::jsonb, NULL, NULL, '["Use count operation with null field to count all items", "sum and avg treat non-numeric values as 0", "min and max fall back to string comparison for non-numeric fields", "countDistinct counts unique non-null values in a field", "concatenate joins string values with comma separator", "When no groupBy, aggregation results are also flattened to top-level output", "Access result: {{core:label.output.total_salary}} (flattened) or {{core:label.output.groups[0].total_salary}} (grouped)", "Group results include group_key, group_count, and all aggregated values"]'::jsonb, '["workflow_builder(action=''add_node'', type=''summarize'', label=''Total Sales'', params={aggregations: [{field: ''amount'', operation: ''sum'', alias: ''total_amount''}, {field: null, operation: ''count'', alias: ''order_count''}], groupBy: []}, connect_after=''Fetch Orders'')", "workflow_builder(action=''add_node'', type=''summarize'', label=''Department Stats'', params={aggregations: [{field: ''salary'', operation: ''avg'', alias: ''avg_salary''}, {field: ''salary'', operation: ''max'', alias: ''max_salary''}, {field: null, operation: ''count'', alias: ''headcount''}], groupBy: [''department'']}, connect_after=''Get Employees'')", "workflow_builder(action=''add_node'', type=''summarize'', label=''Unique Categories'', params={aggregations: [{field: ''category'', operation: ''countDistinct'', alias: ''unique_categories''}, {field: ''name'', operation: ''concatenate'', alias: ''all_names''}], groupBy: []}, connect_after=''List Products'')"]'::jsonb, '["summarize","aggregate","sum","average","count","min","max","group","groupby","statistics","total","distinct","concatenate"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('switch', 'Switch (Case)', 'control_flow', 'core', 'Switch: Route by exact value matching. Evaluates an expression and routes to the case whose value matches. Has ports: case_0, case_1, ..., default. Like a switch statement in programming. Use Decision for boolean conditions, Switch for exact value matching.', '{"cases": {"type": "array", "example": "[{type: ''case'', label: ''Gold'', value: ''gold''}, {type: ''default'', label: ''Other''}]", "required": false, "description": "Array of {type, label, value}. Also accepts: switchCases. Type is ''case'' or ''default''"}, "expression": {"type": "string", "default": "{{input.value}}", "example": "{{mcp:classify.output.category}}", "required": false, "description": "SpEL expression to evaluate. Also accepts: switchExpression. Default: {{input.value}}"}}'::jsonb, '{"evaluations": {"type": "array", "description": "Detailed evaluation results per case"}, "switch_value": {"type": "any", "description": "The evaluated switch expression value"}, "matched_value": {"type": "any", "description": "The case value that matched the switch expression"}, "selected_case": {"type": "string", "description": "The case that matched (e.g. case_0, case_1, default)"}, "skipped_cases": {"type": "array", "description": "Case types that were skipped"}, "selected_case_index": {"type": "number", "description": "Index of the selected case"}, "selected_case_label": {"type": "string", "description": "Label of the selected case"}, "skipped_case_labels": {"type": "array", "description": "Labels of skipped cases"}}'::jsonb, NULL, '{"ports": ["case_0", "case_1", "...", "default"], "pattern": "core:label:case_N, core:label:default"}'::jsonb, '["Exact value matching (not boolean conditions)", "Multiple cases can match", "Include default for unexpected values"]'::jsonb, '["workflow_builder(action=''add_node'', type=''switch'', label=''Route By Plan'', params={expression: ''{{mcp:get_user.output.plan}}'', cases: [{type: ''case'', label: ''Premium'', value: ''premium''}, {type: ''case'', label: ''Basic'', value: ''basic''}, {type: ''default'', label: ''Unknown''}]}, connect_after=''Get User'')"]'::jsonb, '["switch","case","match","route","multi-way","enum"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('table', 'Table Trigger', 'trigger', 'trigger', 'Triggers workflow from table rows, processing each row individually.', '{"limit": {"type": "integer", "required": false}, "filter": {"type": "object", "required": false, "description": "{column, operator, value}"}, "strategy": {"enum": ["receive_one", "receive_all", "batch"], "type": "string", "default": "receive_one", "required": false}, "table_id": {"type": "integer", "required": true, "description": "ID of the table to read from"}}'::jsonb, '{"data": {"type": "array", "description": "Array of row objects from the datasource"}, "hasMore": {"type": "boolean", "description": "Whether more rows exist beyond this batch"}, "totalCount": {"type": "number", "description": "Total number of matching rows"}, "<column_name>": {"type": "varies", "description": "Dynamic fields from datasource columns, copied to top level for SpEL access"}}'::jsonb, NULL, NULL, '["receive_one = per row (default)", "receive_all = all rows as array", "batch = batched processing"]'::jsonb, '["workflow_builder(action=''add_node'', type=''table'', label=''Process Users'', params={table_id: 123})"]'::jsonb, '["table","datasource","database","row","batch","data"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('transform', 'Transform (Data Mapping)', 'control_flow', 'core', 'Transform: Compute new fields from existing data (1:1 mapping). Creates new named values from SpEL expressions. Unlike Aggregate (N→1 collection), Transform computes fields from the current context.', '{"mappings": {"type": "array", "example": "[{label: ''full_name'', expression: ''{{mcp:get_user.output.first_name}} {{mcp:get_user.output.last_name}}''}]", "minItems": 1, "required": true, "description": "Array of {label, expression} defining computed fields. Aliases accepted: fields, transformations, values, outputs. Each item: label/name/field/key for the name, expression/value/expr for the SpEL expression"}}'::jsonb, '{"evaluations": {"type": "array", "description": "Array of mapping evaluations, each with field, expression, resolved_expression, and value"}, "transformed": {"type": "object", "description": "Flattened output object with all computed fields as key-value pairs"}}'::jsonb, NULL, NULL, '["Compute new fields from existing data (1:1 mapping)", "Each mapping.label becomes output field", "Access via {{core:label.output.transformed.<field>}}"]'::jsonb, '["workflow_builder(action=''add_node'', type=''transform'', label=''Build Name'', params={mappings: [{label: ''full_name'', expression: ''{{mcp:get_user.output.first_name}} {{mcp:get_user.output.last_name}}''}, {label: ''greeting'', expression: ''Hello {{mcp:get_user.output.first_name}}''}]}, connect_after=''Get User'')"]'::jsonb, '["transform","map","mapping","compute","calculate","format","convert","reshape"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('update_row', 'Update Row', 'action', 'table', 'Update rows matching a WHERE condition.', '{"set": {"type": "object", "required": true, "description": "{column: new_value}"}, "where": {"type": "object", "required": true, "description": "{column, operator, value}"}, "table_id": {"type": "integer", "required": true}}'::jsonb, '{"updated_at": {"type": "string", "description": "ISO timestamp of update"}, "updated_count": {"type": "number", "description": "Number of rows updated"}}'::jsonb, NULL, NULL, NULL, '["workflow_builder(action=''add_node'', type=''update_row'', label=''Mark Done'', params={table_id: 123, where: {column: ''id'', operator: ''=='', value: ''{{trigger:webhook.output.task_id}}''}, set: {status: ''completed''}}, connect_after=''Webhook'')"]'::jsonb, '["update","modify","edit","set","change","row","table"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('wait', 'Wait', 'control_flow', 'core', 'Wait: Pause workflow execution for a specified duration. Supports human-readable durations (30s, 5m, 1h, 1d) or milliseconds. Useful for rate limiting, polling intervals, or timed delays.', '{"duration": {"type": "string", "example": "30s", "required": true, "description": "How long to wait. Formats: ''30s'', ''5m'', ''1h'', ''1d'', or milliseconds as integer. Also accepts: delay. Alternative: seconds (integer, converted to ms)"}}'::jsonb, '{"waited": {"type": "number", "description": "Duration waited in milliseconds"}, "started_at": {"type": "string", "description": "ISO timestamp when wait started"}, "completed_at": {"type": "string", "description": "ISO timestamp when wait completed"}}'::jsonb, NULL, NULL, '["Use for rate limiting between API calls", "Use in retry loops for delay"]'::jsonb, '["workflow_builder(action=''add_node'', type=''wait'', label=''Wait 30s'', params={duration: ''30s''}, connect_after=''Start'')", "workflow_builder(action=''add_node'', type=''wait'', label=''Rate Limit'', params={delay: ''2s''}, connect_after=''API Call'')"]'::jsonb, '["wait","delay","pause","sleep","timeout","hold","timer"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('webhook', 'Webhook Trigger', 'trigger', 'trigger', 'Triggers workflow via HTTP webhook when an HTTP request is received.', '{"method": {"enum": ["GET", "POST", "PUT", "PATCH", "DELETE"], "type": "string", "default": "POST", "required": false}, "auth_type": {"enum": ["none", "api_key", "basic", "bearer", "hmac"], "type": "string", "default": "none", "required": false}, "auth_config": {"type": "object", "required": false, "description": "Auth config (required when auth_type != none)"}}'::jsonb, '{"query": {"type": "object", "description": "Query string parameters"}, "method": {"type": "string", "description": "HTTP method used (GET, POST, etc.)"}, "headers": {"type": "object", "description": "Webhook request headers"}, "payload": {"type": "object", "description": "Webhook request body"}, "triggered_at": {"type": "string", "description": "ISO timestamp when webhook was received"}}'::jsonb, NULL, NULL, '["HTTP webhooks accept incoming requests from external systems", "Supports auth: none, api_key, basic, bearer, hmac"]'::jsonb, '["workflow_builder(action=''add_node'', type=''webhook'', label=''Incoming Data'')"]'::jsonb, '["webhook","http","api","external","url","post","request","endpoint"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('workflow', 'Workflow Trigger', 'trigger', 'trigger', 'Triggers when another workflow completes. Used for workflow chaining.', '{"trigger_on": {"enum": ["success", "failure", "complete", "any"], "type": "string", "default": "success", "required": false}, "workflow_id": {"type": "uuid", "required": true, "description": "UUID of the parent workflow"}, "input_mapping": {"type": "object", "required": false, "description": "Map parent outputs to inputs"}}'::jsonb, '{"triggeredAt": {"type": "string", "description": "ISO timestamp when trigger fired"}, "<parent_output_key>": {"type": "varies", "description": "All parent workflow output fields are flattened to root level for SpEL access"}}'::jsonb, NULL, NULL, '["Workflow chaining for complex orchestrations", "Can access parent workflow outputs"]'::jsonb, '["workflow_builder(action=''add_node'', type=''workflow'', label=''After Import'', params={workflow_id: ''<uuid>''})"]'::jsonb, '["workflow","chain","cascade","parent","child","trigger"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
INSERT INTO node_type_documentation (type, label, category, variable_prefix, description, parameters, outputs, global_variables, edge_ports, concepts, examples, keywords, enabled, created_at, updated_at) VALUES ('xml', 'XML', 'data_manipulation', 'core', 'Parses XML strings to JSON Maps and builds XML strings from JSON Maps. Supports two operations: xmlToJson (parse XML input into a structured map) and jsonToXml (build an XML string from structured data). Useful for integrating with SOAP/XML APIs or transforming data between XML and JSON formats.', '{"value": {"type": "string", "required": false, "description": "Input value. For xmlToJson: the XML string to parse. For jsonToXml: expression referencing the data to convert. Supports SpEL templates like {{step.output.field}}."}, "operation": {"enum": ["xmlToJson", "jsonToXml"], "type": "string", "default": "xmlToJson", "required": false, "description": "Operation to perform: ''xmlToJson'' (parse XML to JSON map) or ''jsonToXml'' (build XML from JSON map)."}, "rootElement": {"type": "string", "default": "root", "required": false, "description": "Root element name for jsonToXml output. Ignored for xmlToJson."}, "preserveAttributes": {"type": "boolean", "default": false, "required": false, "description": "When true, XML attributes are preserved in the JSON output under an ''@attributes'' key. Only applies to xmlToJson."}}'::jsonb, '{"result": {"type": "any", "description": "Operation result (parsed object, XML string, or extracted value)"}, "success": {"type": "boolean", "description": "Whether the operation succeeded"}, "operation": {"type": "string", "description": "The operation that was performed"}}'::jsonb, NULL, NULL, '["xmlToJson parses an XML string into a nested map structure", "jsonToXml builds an XML string from a map using the specified root element", "Repeated XML elements with the same name are automatically converted to JSON arrays", "XML attributes are only preserved when preserveAttributes is true - they appear under @attributes", "Access parsed result: {{core:label.output.result.field_name}}", "Access XML string: {{core:label.output.result}}", "XXE protection is enabled by default (external entities are blocked)"]'::jsonb, '["workflow_builder(action=''add_node'', type=''xml'', label=''Parse Response'', params={operation: ''xmlToJson'', value: ''{{mcp:call_api.output.body}}'', preserveAttributes: true}, connect_after=''Call API'')", "workflow_builder(action=''add_node'', type=''xml'', label=''Build Payload'', params={operation: ''jsonToXml'', rootElement: ''request'', value: ''transform_output''}, connect_after=''Transform Data'')", "workflow_builder(action=''add_node'', type=''xml'', label=''Parse Config'', params={operation: ''xmlToJson'', value: ''<config><host>localhost</host><port>8080</port></config>''}, connect_after=''Start'')"]'::jsonb, '["xml","json","parse","convert","transform","soap","xmlToJson","jsonToXml","serialize","deserialize","markup"]'::jsonb, true, NOW(), NOW()) ON CONFLICT (type) DO UPDATE SET label = EXCLUDED.label, category = EXCLUDED.category, variable_prefix = EXCLUDED.variable_prefix, description = EXCLUDED.description, parameters = EXCLUDED.parameters, outputs = EXCLUDED.outputs, global_variables = EXCLUDED.global_variables, edge_ports = EXCLUDED.edge_ports, concepts = EXCLUDED.concepts, examples = EXCLUDED.examples, keywords = EXCLUDED.keywords, enabled = EXCLUDED.enabled, updated_at = NOW();
